import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Upload, AlertCircle, Check } from 'lucide-react';

const ImportData: React.FC = () => {
  const { importMatches } = useApp();
  const [jsonContent, setJsonContent] = useState('');
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      if (event.target?.result) {
        setJsonContent(event.target.result as string);
      }
    };
    reader.readAsText(file);
  };

  const handleImport = () => {
    try {
      const parsed = JSON.parse(jsonContent);
      if (!Array.isArray(parsed)) throw new Error("Root must be an array of matches");

      // Basic validation could go here
      importMatches(parsed);
      setStatus('success');
      setJsonContent('');
    } catch (err) {
      console.error(err);
      setStatus('error');
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <h2 className="text-3xl font-bold dark:text-white">Import Match Data</h2>

      <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
        <div className="border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-xl p-8 text-center hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
          <input 
            type="file" 
            accept=".json"
            onChange={handleFileUpload}
            className="hidden" 
            id="file-upload"
          />
          <label htmlFor="file-upload" className="cursor-pointer flex flex-col items-center">
             <div className="bg-pitch-50 dark:bg-pitch-900/30 p-4 rounded-full text-pitch-600 mb-4">
                <Upload size={32} />
             </div>
             <span className="font-bold text-lg dark:text-white">Click to upload JSON</span>
             <span className="text-sm text-gray-500 mt-2">Format: Array of Match objects</span>
          </label>
        </div>

        {jsonContent && (
          <div className="mt-6">
             <div className="bg-gray-50 dark:bg-gray-900 p-4 rounded-lg font-mono text-xs text-gray-600 dark:text-gray-400 max-h-40 overflow-auto mb-4">
                {jsonContent.slice(0, 500)}...
             </div>
             <button 
               onClick={handleImport}
               className="w-full bg-pitch-600 hover:bg-pitch-500 text-white font-bold py-3 rounded-xl transition-colors"
             >
               Process Import
             </button>
          </div>
        )}

        {status === 'success' && (
          <div className="mt-4 p-4 bg-green-50 text-green-700 rounded-lg flex items-center gap-2">
            <Check size={20} /> Data imported successfully!
          </div>
        )}

        {status === 'error' && (
          <div className="mt-4 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2">
            <AlertCircle size={20} /> Invalid JSON format.
          </div>
        )}
      </div>

      <div className="text-sm text-gray-500">
         <p className="font-bold mb-2">Example Format:</p>
         <pre className="bg-gray-100 dark:bg-gray-800 p-4 rounded-lg overflow-x-auto">
{`[
  {
    "id": "1",
    "type": "INTERNAL_FRIENDLY",
    "stadium": "MEDIUM",
    "players": [...]
  }
]`}
         </pre>
      </div>
    </div>
  );
};

