  MEDIUM = 'MEDIUM', // e.g. 7-a-side
  LARGE = 'LARGE', // e.g. 11-a-side
}

export enum Position {
  FW = 'Forward',
  MF = 'Midfielder',
  DF = 'Defender',
  GK = 'Goalkeeper',
}

export interface PlayerStats {
  goals: number;
  assists: number;
  cleanSheets: number; // Only relevant if played as GK
  wins: number;
  draws: number;
  losses: number;
  matchesPlayed: number;
