import React, { createContext, useContext, useState, useCallback, ReactNode } from 'react';
import { X, CheckCircle, AlertCircle, Info } from 'lucide-react';

type ToastType = 'success' | 'error' | 'info';

interface Toast {
  id: string;
  message: string;
  type: ToastType;
}

interface ToastContextType {
  showToast: (message: string, type?: ToastType) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const ToastProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const showToast = useCallback((message: string, type: ToastType = 'success') => {
    const id = Date.now().toString();
    setToasts((prev) => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id));
    }, 3000);
  }, []);

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      <div className="fixed bottom-4 right-4 z-50 flex flex-col gap-2 pointer-events-none">
        {toasts.map((toast) => (
          <div
            key={toast.id}
            className={`
              pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-xl shadow-lg transform transition-all duration-300 animate-slide-up
              ${toast.type === 'success' ? 'bg-emerald-500 text-white' : ''}
              ${toast.type === 'error' ? 'bg-red-500 text-white' : ''}
              ${toast.type === 'info' ? 'bg-blue-500 text-white' : ''}
            `}
          >
            {toast.type === 'success' && <CheckCircle size={18} />}
            {toast.type === 'error' && <AlertCircle size={18} />}
            {toast.type === 'info' && <Info size={18} />}
            <span className="font-medium text-sm">{toast.message}</span>
            <button onClick={() => removeToast(toast.id)} className="opacity-80 hover:opacity-100">
              <X size={14} />
            </button>
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
};

export const useToast = () => {
  const context = useContext(ToastContext);
  if (!context) throw new Error('useToast must be used within a ToastProvider');
  return context;
};

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { Player, Match, MatchType, StadiumSize, Position, PlayerStats, SynergyPair, AppSettings } from '../types';
import { MATCH_TYPE_WEIGHTS, STADIUM_SIZE_WEIGHTS, BASE_POINTS } from '../constants';

interface AppContextType {
  players: Player[];
  matches: Match[];
  settings: AppSettings;
  addPlayer: (player: Player) => void;
  deletePlayer: (id: string) => void;
  updatePlayerAvatar: (id: string, url: string) => void;
  addMatch: (match: Match) => void;
  importMatches: (matches: Match[]) => void;
  updateSettings: (newSettings: AppSettings) => void;
  getPlayerStats: (playerId: string) => PlayerStats;
  getAllPlayerStats: () => (Player & PlayerStats)[];
  getBestSynergy: () => SynergyPair[];
}

const AppContext = createContext<AppContextType | undefined>(undefined);

// Initial Mock Data
const INITIAL_PLAYERS: Player[] = [
  { id: '1', name: 'Tsubasa', position: Position.MF, avatarUrl: 'https://picsum.photos/100/100?random=1' },
  { id: '2', name: 'Hyuga', position: Position.FW, avatarUrl: 'https://picsum.photos/100/100?random=2' },
  { id: '3', name: 'Wakabayashi', position: Position.GK, avatarUrl: 'https://picsum.photos/100/100?random=3' },
  { id: '4', name: 'Misaki', position: Position.MF, avatarUrl: 'https://picsum.photos/100/100?random=4' },
];

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [players, setPlayers] = useState<Player[]>(INITIAL_PLAYERS);
  const [matches, setMatches] = useState<Match[]>([]);
  const [settings, setSettings] = useState<AppSettings>({
    matchTypeWeights: { ...MATCH_TYPE_WEIGHTS },
    stadiumSizeWeights: { ...STADIUM_SIZE_WEIGHTS },
    basePoints: { ...BASE_POINTS }
  });

  const addPlayer = (player: Player) => {
    setPlayers(prev => [...prev, player]);
  };

  const deletePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const updatePlayerAvatar = (id: string, url: string) => {
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, avatarUrl: url } : p));
  };

  const addMatch = (match: Match) => {
    setMatches(prev => [match, ...prev]); // Newest first
  };

  const importMatches = (newMatches: Match[]) => {
      // Avoid duplicates based on ID
      const existingIds = new Set(matches.map(m => m.id));
      const uniqueNewMatches = newMatches.filter(m => !existingIds.has(m.id));
      setMatches(prev => [...uniqueNewMatches, ...prev]);
  };

  const updateSettings = (newSettings: AppSettings) => {
    setSettings(newSettings);
  };

  const getPlayerStats = (playerId: string): PlayerStats => {
    const stats: PlayerStats = {
      goals: 0,
      assists: 0,
      cleanSheets: 0,
      wins: 0,
      draws: 0,
      losses: 0,
      matchesPlayed: 0,
      weightedRating: 0,
    };

    matches.forEach(match => {
      const pMatch = match.players.find(p => p.playerId === playerId);
      if (!pMatch) return;

      stats.matchesPlayed += 1;
      stats.goals += pMatch.goals;
      stats.assists += pMatch.assists;
      if (pMatch.isGK && pMatch.cleanSheet) stats.cleanSheets += 1;

      // Result
      const isTeamA = pMatch.team === 'A';
      const myScore = isTeamA ? match.scoreA : match.scoreB;
      const oppScore = isTeamA ? match.scoreB : match.scoreA;

      if (myScore > oppScore) stats.wins += 1;
      else if (myScore === oppScore) stats.draws += 1;
      else stats.losses += 1;

      // Weighted Rating Calculation
      const matchMultiplier = settings.matchTypeWeights[match.type] * settings.stadiumSizeWeights[match.stadium];

      let matchRating = 0;
      matchRating += pMatch.goals * settings.basePoints.GOAL;
      matchRating += pMatch.assists * settings.basePoints.ASSIST;
      if (pMatch.isGK && pMatch.cleanSheet) matchRating += settings.basePoints.CLEAN_SHEET;

      if (myScore > oppScore) matchRating += settings.basePoints.WIN;
      else if (myScore === oppScore) matchRating += settings.basePoints.DRAW;

      stats.weightedRating += (matchRating * matchMultiplier);
    });

    return stats;
  };

  const getAllPlayerStats = () => {
    return players.map(p => ({
      ...p,
      ...getPlayerStats(p.id)
    }));
  };

  // O(N^2 * M) complexity - acceptable for small teams (e.g. < 50 players, < 100 matches)
  const getBestSynergy = (): SynergyPair[] => {
    const pairs: Map<string, SynergyPair> = new Map();

    matches.forEach(match => {
      // Group players by team for this match
      const teamA = match.players.filter(p => p.team === 'A');
      const teamB = match.players.filter(p => p.team === 'B');

      const processTeam = (teamMembers: typeof teamA, isWin: boolean) => {
        for (let i = 0; i < teamMembers.length; i++) {
          for (let j = i + 1; j < teamMembers.length; j++) {
            const p1 = teamMembers[i].playerId;
            const p2 = teamMembers[j].playerId;
            // Create a consistent key regardless of order
            const key = [p1, p2].sort().join('_');

            if (!pairs.has(key)) {
              pairs.set(key, { 
                player1Id: p1 < p2 ? p1 : p2, 
                player2Id: p1 < p2 ? p2 : p1, 
                matchesTogether: 0, 
                winsTogether: 0, 
                winRate: 0 
              });
            }

            const current = pairs.get(key)!;
            current.matchesTogether += 1;
            if (isWin) current.winsTogether += 1;
          }
        }
      };

      const winA = match.scoreA > match.scoreB;
      const winB = match.scoreB > match.scoreA;

      processTeam(teamA, winA);
      processTeam(teamB, winB);
    });

    return Array.from(pairs.values())
      .map(pair => ({ ...pair, winRate: pair.matchesTogether > 0 ? (pair.winsTogether / pair.matchesTogether) * 100 : 0 }))
      .filter(pair => pair.matchesTogether >= 2) // Minimum matches together threshold
      .sort((a, b) => b.winRate - a.winRate);
  };

  return (
    <AppContext.Provider value={{ 
      players, 
      matches, 
      settings,
      addPlayer, 
      deletePlayer,
      updatePlayerAvatar,
      addMatch, 
      importMatches,
      updateSettings,
      getPlayerStats,
      getAllPlayerStats,
      getBestSynergy
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

