  const { players, addPlayer, updatePlayerAvatar, deletePlayer } = useApp();
  const { showToast } = useToast();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newPlayerName, setNewPlayerName] = useState('');
  const [newPlayerPosition, setNewPlayerPosition] = useState<Position>(Position.MF);

  const [generatingId, setGeneratingId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [searchQuery, setSearchQuery] = useState('');

  const filteredPlayers = players.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleAddPlayer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPlayerName) return;

    const newPlayer: Player = {
      id: Date.now().toString(),
      name: newPlayerName,
      position: newPlayerPosition,
      avatarUrl: `https://ui-avatars.com/api/?name=${newPlayerName}&background=random`
    };

    addPlayer(newPlayer);
    setNewPlayerName('');
    setIsModalOpen(false);
    showToast('Player recruited successfully!');
  };

  const handleDeletePlayer = (id: string, name: string) => {
    if (confirm(`Are you sure you want to remove ${name} from the squad?`)) {
      deletePlayer(id);
      showToast(`${name} has been removed.`, 'info');
    }
  };

  const handleGenerateAvatar = async (player: Player) => {
    if (generatingId) return; 
    setGeneratingId(player.id);

    try {
        let desc = "";
        if (player.position === Position.GK) desc = "wearing goalkeeper gloves, focused, defending goal";
        else if (player.position === Position.FW) desc = "striking a ball, aggressive striker pose";
        else desc = "dribbling a football, dynamic midfield action";

        const imageUrl = await generatePlayerAvatar(player.name, desc);
        updatePlayerAvatar(player.id, imageUrl);
        showToast('New avatar generated!', 'success');
    } catch (err) {
        showToast("Failed to generate avatar. Check API Key.", 'error');
    } finally {
        setGeneratingId(null);
    }
  };

  const positionColor = (pos: Position) => {
    switch (pos) {
        case Position.GK: return 'bg-yellow-500 text-yellow-50 border-yellow-200';
        case Position.DF: return 'bg-blue-500 text-blue-50 border-blue-200';
        case Position.MF: return 'bg-emerald-500 text-emerald-50 border-emerald-200';
        case Position.FW: return 'bg-red-500 text-red-50 border-red-200';
        default: return 'bg-gray-500';
    }
  };

  return (
    <div className="space-y-6">
      {/* Header Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-3xl font-bold dark:text-white">Squad</h2>

        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
          {/* Search */}
          <div className="relative flex-1 sm:w-64">
             <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
             <input 
                type="text" 
                placeholder="Find player..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white"
             />
          </div>

          {/* View Toggle */}
          <div className="flex bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-1">
             <button 
                onClick={() => setViewMode('grid')}
                className={`p-2 rounded ${viewMode === 'grid' ? 'bg-pitch-100 text-pitch-600 dark:bg-pitch-900/30 dark:text-pitch-400' : 'text-gray-400 hover:text-gray-600'}`}
             >
                <LayoutGrid size={20} />
             </button>
             <button 
                onClick={() => setViewMode('list')}
                className={`p-2 rounded ${viewMode === 'list' ? 'bg-pitch-100 text-pitch-600 dark:bg-pitch-900/30 dark:text-pitch-400' : 'text-gray-400 hover:text-gray-600'}`}
             >
                <List size={20} />
             </button>
          </div>

          <button
            onClick={() => setIsModalOpen(true)}
            className="bg-pitch-600 hover:bg-pitch-500 text-white px-4 py-2 rounded-lg flex items-center justify-center gap-2 shadow-lg transition-all"
          >
            <UserPlus size={20} />
            Add Player
          </button>
        </div>
      </div>

      {filteredPlayers.length === 0 && (
         <div className="text-center py-12 text-gray-500 dark:text-gray-400 bg-white dark:bg-gray-800 rounded-2xl border border-dashed border-gray-300 dark:border-gray-700">
             <p>No players found.</p>
         </div>
      )}

      {/* Grid View */}
      {viewMode === 'grid' && (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {filteredPlayers.map((player) => (
            <div key={player.id} className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm hover:shadow-xl transition-all duration-300 overflow-hidden border border-gray-100 dark:border-gray-700 group">
              <div className="relative h-48 bg-gray-100 dark:bg-gray-900 overflow-hidden">
                  <img 
                      src={player.avatarUrl} 
                      alt={player.name} 
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                  />
                  <div className="absolute top-2 right-2">
                      <span className={`${positionColor(player.position)} border px-2 py-1 rounded-full text-xs font-bold uppercase tracking-wider shadow-sm`}>
                          {player.position}
                      </span>
                  </div>
                  <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-2">
                      <button 
                          onClick={() => handleGenerateAvatar(player)}
                          disabled={generatingId === player.id}
                          className="bg-white text-pitch-600 px-4 py-2 rounded-full font-bold flex items-center gap-2 hover:bg-gray-100 transform hover:scale-105 transition-all text-sm"
                      >
                          {generatingId === player.id ? <span className="animate-spin">⌛</span> : <Sparkles size={14} />}
                          AI Avatar
                      </button>
                      <button 
                          onClick={() => handleDeletePlayer(player.id, player.name)}
                          className="bg-red-500 text-white px-4 py-2 rounded-full font-bold flex items-center gap-2 hover:bg-red-600 transform hover:scale-105 transition-all text-sm"
                      >
                          <Trash2 size={14} /> Remove
                      </button>
                  </div>
              </div>
              <div className="p-4">
                <h3 className="text-xl font-bold dark:text-white truncate">{player.name}</h3>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-1">
                   <Shirt size={14} /> #{player.id.slice(-3)}
                </p>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* List View */}
      {viewMode === 'list' && (
         <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden">
            <div className="overflow-x-auto">
               <table className="w-full text-left">
                  <thead className="bg-gray-50 dark:bg-gray-900/50 text-gray-500 dark:text-gray-400 uppercase text-xs">
                     <tr>
                        <th className="p-4 font-medium">Player</th>
                        <th className="p-4 font-medium">Position</th>
                        <th className="p-4 font-medium">ID</th>
                        <th className="p-4 font-medium text-right">Actions</th>
                     </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                     {filteredPlayers.map(player => (
                        <tr key={player.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/30 transition-colors">
                           <td className="p-4">
                              <div className="flex items-center gap-3">
                                 <img src={player.avatarUrl} className="w-10 h-10 rounded-full object-cover bg-gray-100" alt={player.name} />
                                 <span className="font-bold dark:text-white">{player.name}</span>
                              </div>
                           </td>
                           <td className="p-4">
                              <span className={`${positionColor(player.position)} px-2 py-1 rounded-full text-xs font-bold uppercase`}>
                                 {player.position}
                              </span>
                           </td>
                           <td className="p-4 text-gray-500 dark:text-gray-400 font-mono text-sm">
                              #{player.id.slice(-4)}
                           </td>
                           <td className="p-4 text-right">
                              <div className="flex items-center justify-end gap-2">
                                 <button 
                                    onClick={() => handleGenerateAvatar(player)}
                                    disabled={generatingId === player.id}
                                    title="Generate Avatar"
                                    className="p-2 text-pitch-600 hover:bg-pitch-50 dark:hover:bg-pitch-900/30 rounded-lg transition-colors"
                                 >
                                    {generatingId === player.id ? <span className="animate-spin text-xs">⌛</span> : <Sparkles size={18} />}
                                 </button>
                                 <button 
                                    onClick={() => handleDeletePlayer(player.id, player.name)}
                                    title="Remove Player"
                                    className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-lg transition-colors"
                                 >
                                    <Trash2 size={18} />
                                 </button>
                              </div>
                           </td>
                        </tr>
                     ))}
                  </tbody>
               </table>
            </div>
         </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl w-full max-w-md shadow-2xl border dark:border-gray-700 animate-slide-up">
            <h3 className="text-2xl font-bold mb-6 dark:text-white">Recruit New Player</h3>
            <form onSubmit={handleAddPlayer} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Name</label>
                <input
                  type="text"
                  required
                  autoFocus
                  className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white transition-all"
                  value={newPlayerName}
                  onChange={(e) => setNewPlayerName(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Position</label>
                <select
                  className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white transition-all"
                  value={newPlayerPosition}
                  onChange={(e) => setNewPlayerPosition(e.target.value as Position)}
                >
                  {Object.values(Position).map((pos) => (
                    <option key={pos} value={pos}>{pos}</option>
                  ))}
                </select>
              </div>
              <div className="flex gap-3 mt-6">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="flex-1 px-4 py-2 bg-pitch-600 text-white rounded-lg hover:bg-pitch-500 font-medium shadow-md transition-colors"
                >
                  Add to Squad
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default PlayerList;

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Match, MatchType, StadiumSize, MatchPlayerStats } from '../types';
import { Save, Search } from 'lucide-react';
import { useToast } from '../context/ToastContext';

const MatchManager: React.FC = () => {
  const { players, addMatch } = useApp();
  const { showToast } = useToast();

  const [step, setStep] = useState<1 | 2>(1); // 1: Setup, 2: Stats

  // Setup State
  const [matchType, setMatchType] = useState<MatchType>(MatchType.INTERNAL_FRIENDLY);
  const [stadium, setStadium] = useState<StadiumSize>(StadiumSize.MEDIUM);
  const [teamAName, setTeamAName] = useState('Team A');
  const [teamBName, setTeamBName] = useState('Team B');
  const [selectedPlayers, setSelectedPlayers] = useState<{ id: string, team: 'A' | 'B' }[]>([]);

  // Search State for Squad Selection
  const [squadSearch, setSquadSearch] = useState('');

  // Stats State
  const [scoreA, setScoreA] = useState(0);
  const [scoreB, setScoreB] = useState(0);
  const [playerPerformances, setPlayerPerformances] = useState<Record<string, { goals: number, assists: number, isGK: boolean, cleanSheet: boolean }>>({});

  const togglePlayerSelection = (playerId: string, team: 'A' | 'B') => {
    setSelectedPlayers(prev => {
      const exists = prev.find(p => p.id === playerId);
      if (exists) {
        if (exists.team === team) {
          // Deselect
          return prev.filter(p => p.id !== playerId);
        } else {
          // Switch team
          return prev.map(p => p.id === playerId ? { ...p, team } : p);
        }
      } else {
        // Add
        return [...prev, { id: playerId, team }];
      }
    });
  };

  const initializePerformance = () => {
    const perfs: typeof playerPerformances = {};
    selectedPlayers.forEach(p => {
      perfs[p.id] = { goals: 0, assists: 0, isGK: false, cleanSheet: false };
    });
    setPlayerPerformances(perfs);
    setStep(2);
  };

  const updateStat = (playerId: string, field: keyof typeof playerPerformances[string], value: any) => {
    setPlayerPerformances(prev => ({
      ...prev,
      [playerId]: { ...prev[playerId], [field]: value }
    }));
  };

  const handleFinishMatch = () => {
    const matchPlayers: MatchPlayerStats[] = selectedPlayers.map(sp => ({
      playerId: sp.id,
      team: sp.team,
      ...playerPerformances[sp.id]
    }));

    const newMatch: Match = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      type: matchType,
      stadium: stadium,
      teamAName,
      teamBName,
      scoreA,
      scoreB,
      players: matchPlayers
    };

    addMatch(newMatch);
    // Reset
    setStep(1);
    setScoreA(0);
    setScoreB(0);
    setSelectedPlayers([]);
    showToast("Match saved successfully!", "success");
  };

  const teamAPlayers = selectedPlayers.filter(p => p.team === 'A');
  const teamBPlayers = selectedPlayers.filter(p => p.team === 'B');

  const filteredSquadList = players.filter(p => p.name.toLowerCase().includes(squadSearch.toLowerCase()));

  if (step === 1) {
    return (
      <div className="space-y-8 animate-fade-in">
        <h2 className="text-3xl font-bold dark:text-white">New Match Setup</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <h3 className="font-bold mb-4 dark:text-gray-200">Match Details</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm text-gray-500 mb-1">Type</label>
                <select 
                  className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                  value={matchType} onChange={(e) => setMatchType(e.target.value as MatchType)}>
                  {Object.values(MatchType).map(t => <option key={t} value={t}>{t.replace('_', ' ')}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm text-gray-500 mb-1">Stadium</label>
                <select 
                  className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                  value={stadium} onChange={(e) => setStadium(e.target.value as StadiumSize)}>
                  {Object.values(StadiumSize).map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div className="flex gap-4">
                <div className="flex-1">
                   <label className="block text-sm text-gray-500 mb-1">Team A Name</label>
                   <input className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white" value={teamAName} onChange={e => setTeamAName(e.target.value)} />
                </div>
                <div className="flex-1">
                   <label className="block text-sm text-gray-500 mb-1">Team B Name</label>
                   <input className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white" value={teamBName} onChange={e => setTeamBName(e.target.value)} />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col justify-between">
             <div>
                <h3 className="font-bold mb-4 dark:text-gray-200">Summary</h3>
                <div className="flex justify-between items-center bg-gray-50 dark:bg-gray-900 p-4 rounded-lg mb-4">
                    <div className="text-center">
                        <div className="text-2xl font-bold text-pitch-600">{teamAPlayers.length}</div>
                        <div className="text-xs text-gray-500">{teamAName}</div>
                    </div>
                    <div className="text-gray-400 font-light">vs</div>
                    <div className="text-center">
                        <div className="text-2xl font-bold text-pitch-600">{teamBPlayers.length}</div>
                        <div className="text-xs text-gray-500">{teamBName}</div>
                    </div>
                </div>
             </div>
             <button 
                disabled={selectedPlayers.length === 0}
                onClick={initializePerformance}
                className="w-full py-3 bg-pitch-600 disabled:bg-gray-400 text-white rounded-xl font-bold hover:bg-pitch-500 transition-colors shadow-lg disabled:shadow-none"
             >
                Start Match Tracking
             </button>
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
           <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
               <h3 className="font-bold dark:text-gray-200">Squad Selection</h3>
               <div className="relative w-full sm:w-64">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={16} />
                    <input 
                        type="text" 
                        placeholder="Search players..." 
                        value={squadSearch}
                        onChange={(e) => setSquadSearch(e.target.value)}
                        className="w-full pl-9 pr-4 py-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-1 focus:ring-pitch-500 outline-none dark:text-white"
                    />
               </div>
           </div>

           <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 max-h-96 overflow-y-auto pr-2">
              {filteredSquadList.map(p => {
                const selection = selectedPlayers.find(sp => sp.id === p.id);
                return (
                  <div key={p.id} className={`p-3 rounded-lg border flex flex-col items-center gap-2 transition-all ${selection ? 'border-pitch-500 bg-pitch-50 dark:bg-pitch-900/20' : 'border-gray-200 dark:border-gray-700'}`}>
                      <img src={p.avatarUrl} className="w-10 h-10 rounded-full object-cover" alt={p.name} />
                      <span className="font-medium text-sm dark:text-white truncate w-full text-center">{p.name}</span>
                      <div className="flex gap-2 w-full">
                         <button 
                            onClick={() => togglePlayerSelection(p.id, 'A')}
                            className={`flex-1 text-xs py-1.5 font-medium rounded transition-colors ${selection?.team === 'A' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                            Team A
                         </button>
                         <button 
                            onClick={() => togglePlayerSelection(p.id, 'B')}
                            className={`flex-1 text-xs py-1.5 font-medium rounded transition-colors ${selection?.team === 'B' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                            Team B
                         </button>
                      </div>
                  </div>
                )
              })}
           </div>
           {filteredSquadList.length === 0 && (
               <div className="text-center py-8 text-gray-400">No players found matching "{squadSearch}"</div>
           )}
        </div>
      </div>
    );
  }

  // Step 2: Stats Input
  return (
    <div className="space-y-6 animate-fade-in">
       <div className="flex justify-between items-center">
         <h2 className="text-3xl font-bold dark:text-white">Match Result</h2>
         <button onClick={() => setStep(1)} className="text-gray-500 hover:text-gray-700 dark:hover:text-gray-300">Cancel</button>
       </div>

       {/* Scoreboard Input */}
       <div className="flex justify-center items-center gap-4 sm:gap-8 bg-jersey-dark p-6 sm:p-8 rounded-2xl text-white shadow-lg">
          <div className="text-center">
             <h3 className="text-lg sm:text-xl mb-2 text-pitch-400 font-bold">{teamAName}</h3>
             <input 
                type="number" 
                min="0"
                className="w-20 h-20 sm:w-24 sm:h-24 text-center text-4xl sm:text-5xl font-bold bg-white/10 rounded-xl focus:outline-none focus:ring-2 focus:ring-pitch-500 transition-all"
                value={scoreA}
                onChange={e => setScoreA(parseInt(e.target.value) || 0)}
             />
          </div>
          <div className="text-2xl sm:text-4xl font-thin text-gray-500">-</div>
          <div className="text-center">
             <h3 className="text-lg sm:text-xl mb-2 text-pitch-400 font-bold">{teamBName}</h3>
             <input 
                type="number" 
                min="0"
                className="w-20 h-20 sm:w-24 sm:h-24 text-center text-4xl sm:text-5xl font-bold bg-white/10 rounded-xl focus:outline-none focus:ring-2 focus:ring-pitch-500 transition-all"
                value={scoreB}
                onChange={e => setScoreB(parseInt(e.target.value) || 0)}
             />
          </div>
       </div>

       {/* Player Stats Input */}
       <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {[
              { team: 'A', name: teamAName, players: teamAPlayers }, 
              { team: 'B', name: teamBName, players: teamBPlayers }
            ].map((group) => (
            <div key={group.team} className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
               <h3 className="font-bold text-xl mb-4 text-pitch-600 border-b border-gray-100 dark:border-gray-700 pb-2">{group.name} Stats</h3>
               <div className="space-y-4">
                  {group.players.map(sp => {
                     const p = players.find(x => x.id === sp.id)!;
                     const stats = playerPerformances[p.id];
                     return (
                        <div key={p.id} className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-900 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors">
                           <img src={p.avatarUrl} className="w-10 h-10 rounded-full bg-white" alt={p.name} />
                           <div className="flex-1 min-w-0">
                             <div className="font-bold truncate dark:text-white text-sm">{p.name}</div>
                             <div className="text-xs text-gray-500">{p.position}</div>
                           </div>

                           {/* Goal Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">Goals</span>
                              <input 
                                type="number" min="0" className="w-12 p-1 text-center text-sm border rounded dark:bg-gray-800 dark:border-gray-600 dark:text-white focus:border-pitch-500 outline-none"
                                value={stats.goals}
                                onChange={e => updateStat(p.id, 'goals', parseInt(e.target.value))}
                              />
                           </div>

                           {/* Assist Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">Asst</span>
                              <input 
                                type="number" min="0" className="w-12 p-1 text-center text-sm border rounded dark:bg-gray-800 dark:border-gray-600 dark:text-white focus:border-pitch-500 outline-none"
                                value={stats.assists}
                                onChange={e => updateStat(p.id, 'assists', parseInt(e.target.value))}
                              />
                           </div>

                           {/* GK Toggle */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">GK</span>
                              <input 
                                type="checkbox" className="w-5 h-5 accent-pitch-600 rounded cursor-pointer"
                                checked={stats.isGK}
                                onChange={e => updateStat(p.id, 'isGK', e.target.checked)}
                              />
                           </div>

                           {/* Clean Sheet (Only if GK) */}
                           {stats.isGK && (
                             <div className="flex flex-col items-center animate-fade-in">
                                <span className="text-[10px] text-gray-400 mb-0.5 uppercase">CS</span>
                                <input 
                                  type="checkbox" className="w-5 h-5 accent-pitch-600 rounded cursor-pointer"
                                  checked={stats.cleanSheet}
                                  onChange={e => updateStat(p.id, 'cleanSheet', e.target.checked)}
                                />
                             </div>
                           )}
                        </div>
                     )
                  })}
               </div>
            </div>
          ))}
       </div>

       <div className="flex justify-end pt-6">
          <button 
            onClick={handleFinishMatch}
            className="bg-pitch-600 hover:bg-pitch-500 text-white px-8 py-4 rounded-xl font-bold text-lg shadow-xl flex items-center gap-3 transition-transform hover:scale-105"
          >
            <Save size={24} />
            Save Match Results
          </button>
       </div>
    </div>
  );
};

