import { MATCH_TYPE_WEIGHTS, STADIUM_SIZE_WEIGHTS, BASE_POINTS } from '../constants';
import { useToast } from '../context/ToastContext';

const Settings: React.FC = () => {
  const { settings, updateSettings } = useApp();
  const { showToast } = useToast();

  // Local state for the form to avoid excessive context updates while typing
  const [localSettings, setLocalSettings] = useState(settings);

  // Sync local state if context settings change (e.g. from a reset elsewhere)
  useEffect(() => {
    setLocalSettings(settings);
  }, [settings]);

  const handleSave = () => {
    updateSettings(localSettings);
    showToast('Configuration saved. Stats recalculated.', 'success');
  };

  const handleReset = () => {
    if (confirm('Are you sure you want to reset all weightings to default values?')) {
        const defaults = {
            matchTypeWeights: { ...MATCH_TYPE_WEIGHTS },
            stadiumSizeWeights: { ...STADIUM_SIZE_WEIGHTS },
            basePoints: { ...BASE_POINTS }
        };
        setLocalSettings(defaults);
        updateSettings(defaults);
        showToast('Configuration reset to defaults.', 'info');
    }
  };

  const updateMatchTypeWeight = (type: MatchType, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        matchTypeWeights: {
            ...prev.matchTypeWeights,
            [type]: parseFloat(val) || 0
        }
    }));
  };

  const updateStadiumWeight = (size: StadiumSize, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        stadiumSizeWeights: {
            ...prev.stadiumSizeWeights,
            [size]: parseFloat(val) || 0
        }
    }));
  };

  const updateBasePoint = (key: keyof typeof BASE_POINTS, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        basePoints: {
            ...prev.basePoints,
            [key]: parseFloat(val) || 0
        }
    }));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="flex items-center justify-between">
         <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
             <SettingsIcon className="text-pitch-600" size={32} />
             Stat Configuration
