                        <div>
                           <div className="font-bold dark:text-white">{stadium.name}</div>
                           <div className="text-xs text-gray-500">{stadium.size}</div>
                        </div>
                        <button 
                           onClick={() => handleDeleteStadium(stadium.id)}
                           className="text-gray-400 hover:text-red-500 p-2 rounded-full hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                        >
                           <Trash2 size={16} />
                        </button>
                     </div>
                  ))}
               </div>
            </div>
         </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">

        {/* Match Type Multipliers */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <h3 className="font-bold text-xl mb-6 dark:text-white border-b dark:border-gray-700 pb-2">Match Multipliers</h3>
            <div className="space-y-4">
                {Object.values(MatchType).map((type) => (
                    <div key={type} className="flex justify-between items-center">
                        <label className="text-gray-600 dark:text-gray-300 font-medium">
                            {type.replace('_', ' ')}
                        </label>
                        <input 
                            type="number" step="0.1"
                            value={localSettings.matchTypeWeights[type]}
                            onChange={(e) => updateMatchTypeWeight(type, e.target.value)}
                            className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                        />
                    </div>
                ))}
            </div>

            <h3 className="font-bold text-xl mt-8 mb-6 dark:text-white border-b dark:border-gray-700 pb-2">Stadium Multipliers</h3>
            <div className="space-y-4">
                {Object.values(StadiumSize).map((size) => (
                    <div key={size} className="flex justify-between items-center">
                        <label className="text-gray-600 dark:text-gray-300 font-medium">
                            {size} Pitch
                        </label>
                        <input 
                            type="number" step="0.1"
                            value={localSettings.stadiumSizeWeights[size]}
                            onChange={(e) => updateStadiumWeight(size, e.target.value)}
                            className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                        />
                    </div>
                ))}
            </div>
        </div>

        {/* Base Points */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <h3 className="font-bold text-xl mb-6 dark:text-white border-b dark:border-gray-700 pb-2">Base Points</h3>
            <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <label className="text-gray-600 dark:text-gray-300 font-medium">Goal Scored</label>
                    <input 
                        type="number"
                        value={localSettings.basePoints.GOAL}
                        onChange={(e) => updateBasePoint('GOAL', e.target.value)}
