                <div className="flex justify-between items-center">
                    <label className="text-gray-600 dark:text-gray-300 font-medium">Assist</label>
                    <input 
                        type="number"
                        value={localSettings.basePoints.ASSIST}
                        onChange={(e) => updateBasePoint('ASSIST', e.target.value)}
                        className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
