                        <span className="text-sm font-mono w-4 text-center">{ownGoalsB}</span>
                        <button onClick={() => setOwnGoalsB(ownGoalsB + 1)} className="hover:text-pitch-400"><PlusCircle size={14}/></button>
                    </div>
