               <div className="flex justify-between items-center mb-4 border-b border-gray-100 dark:border-gray-700 pb-2">
                   <h3 className="font-bold text-xl text-pitch-600">{group.name} Stats</h3>
                   <div className="text-sm text-gray-400">Total: <span className="text-gray-900 dark:text-white font-bold">{group.total}</span></div>
               </div>

               <div className="space-y-4">
                  {group.players.map(sp => {
                     const p = players.find(x => x.id === sp.id)!;
                     const stats = playerPerformances[p.id];
                     return (
                        <div key={p.id} className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-900 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors">
                           <img src={p.avatarUrl} className="w-10 h-10 rounded-full bg-white" alt={p.name} />
                           <div className="flex-1 min-w-0">
                             <div className="font-bold truncate dark:text-white text-sm">{p.name}</div>
                             <div className="text-xs text-gray-500">{p.position}</div>
                           </div>

                           {/* Goal Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">Goals</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border rounded dark:bg-gray-800 dark:border-gray-600 dark:text-white focus:border-pitch-500 outline-none"
                                value={stats.goals}
                                onChange={e => updateStat(p.id, 'goals', parseInt(e.target.value))}
                              />
                           </div>

                           {/* Assist Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">Asst</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border rounded dark:bg-gray-800 dark:border-gray-600 dark:text-white focus:border-pitch-500 outline-none"
                                value={stats.assists}
                                onChange={e => updateStat(p.id, 'assists', parseInt(e.target.value))}
                              />
                           </div>

                           {/* Own Goal Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-red-400 mb-0.5 uppercase font-bold" title="Own Goal">OG</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border border-red-200 dark:border-red-900 rounded dark:bg-gray-800 dark:text-white focus:border-red-500 outline-none"
                                value={stats.ownGoals}
                                onChange={e => updateStat(p.id, 'ownGoals', parseInt(e.target.value))}
                              />
                           </div>

                           {/* GK Toggle */}
                           <div className="flex flex-col items-center px-1">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">GK</span>
                              <input 
                                type="checkbox" className="w-5 h-5 accent-pitch-600 rounded cursor-pointer"
                                checked={stats.isGK}
                                onChange={e => updateStat(p.id, 'isGK', e.target.checked)}
                              />
                           </div>

                           {/* Clean Sheet (Only if GK) */}
                           {stats.isGK && (
                             <div className="flex flex-col items-center animate-fade-in px-1">
                                <span className="text-[10px] text-gray-400 mb-0.5 uppercase">CS</span>
                                <input 
                                  type="checkbox" className="w-5 h-5 accent-pitch-600 rounded cursor-pointer"
                                  checked={stats.cleanSheet}
                                  onChange={e => updateStat(p.id, 'cleanSheet', e.target.checked)}
                                />
                             </div>
                           )}
                        </div>
                     )
                  })}
               </div>
            </div>
          ))}
       </div>

       <div className="flex justify-end pt-6">
          <button 
            onClick={handleFinishMatch}
            className="bg-pitch-600 hover:bg-pitch-500 text-white px-8 py-4 rounded-xl font-bold text-lg shadow-xl flex items-center gap-3 transition-transform hover:scale-105"
          >
            <Save size={24} />
            Save Match Results
          </button>
       </div>
    </div>
  );
};

export default MatchManager;

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { MatchType, StadiumSize, Stadium } from '../types';
import { Save, RotateCcw, Settings as SettingsIcon, MapPin, Plus, Trash2 } from 'lucide-react';
import { MATCH_TYPE_WEIGHTS, STADIUM_SIZE_WEIGHTS, BASE_POINTS } from '../constants';
import { useToast } from '../context/ToastContext';

const Settings: React.FC = () => {
  const { settings, updateSettings, stadiums, addStadium, deleteStadium } = useApp();
  const { showToast } = useToast();

  // Local state for the form to avoid excessive context updates while typing
  const [localSettings, setLocalSettings] = useState(settings);

  // State for new stadium form
  const [newStadiumName, setNewStadiumName] = useState('');
  const [newStadiumSize, setNewStadiumSize] = useState<StadiumSize>(StadiumSize.MEDIUM);

  // Sync local state if context settings change (e.g. from a reset elsewhere)
  useEffect(() => {
    setLocalSettings(settings);
  }, [settings]);

  const handleSave = () => {
    updateSettings(localSettings);
    showToast('Configuration saved. Stats recalculated.', 'success');
  };

  const handleReset = () => {
    if (confirm('Are you sure you want to reset all weightings to default values?')) {
        const defaults = {
            matchTypeWeights: { ...MATCH_TYPE_WEIGHTS },
            stadiumSizeWeights: { ...STADIUM_SIZE_WEIGHTS },
            basePoints: { ...BASE_POINTS }
        };
        setLocalSettings(defaults);
        updateSettings(defaults);
        showToast('Configuration reset to defaults.', 'info');
    }
  };

  const handleAddStadium = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newStadiumName.trim()) return;

    const newStadium: Stadium = {
      id: Date.now().toString(),
      name: newStadiumName,
      size: newStadiumSize
    };
    addStadium(newStadium);
    setNewStadiumName('');
    showToast('Stadium added successfully!', 'success');
  };

  const handleDeleteStadium = (id: string) => {
    if (confirm('Remove this stadium?')) {
      deleteStadium(id);
      showToast('Stadium removed.', 'info');
    }
  };

  const updateMatchTypeWeight = (type: MatchType, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        matchTypeWeights: {
            ...prev.matchTypeWeights,
            [type]: parseFloat(val) || 0
        }
    }));
  };

  const updateStadiumWeight = (size: StadiumSize, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        stadiumSizeWeights: {
            ...prev.stadiumSizeWeights,
            [size]: parseFloat(val) || 0
        }
    }));
  };

  const updateBasePoint = (key: keyof typeof BASE_POINTS, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        basePoints: {
            ...prev.basePoints,
            [key]: parseFloat(val) || 0
        }
    }));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-12">
      <div className="flex items-center justify-between">
         <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
             <SettingsIcon className="text-pitch-600" size={32} />
             Settings
         </h2>
         <button 
            onClick={handleReset}
            className="flex items-center gap-2 px-4 py-2 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
         >
            <RotateCcw size={18} />
            Reset Defaults
         </button>
      </div>

      {/* Stadium Management Section */}
      <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
         <div className="flex items-center gap-2 mb-6 border-b dark:border-gray-700 pb-2">
            <MapPin className="text-pitch-600" size={24} />
            <h3 className="font-bold text-xl dark:text-white">Stadium Management</h3>
         </div>

         <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
               <h4 className="font-medium text-gray-500 dark:text-gray-400 mb-3 text-sm uppercase tracking-wider">Add New Venue</h4>
               <form onSubmit={handleAddStadium} className="space-y-4">
                  <div>
                    <input 
                       type="text" 
                       placeholder="Stadium Name"
                       className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg outline-none focus:ring-2 focus:ring-pitch-500 dark:text-white"
                       value={newStadiumName}
                       onChange={(e) => setNewStadiumName(e.target.value)}
                    />
                  </div>
                  <div>
                    <select
                      className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg outline-none focus:ring-2 focus:ring-pitch-500 dark:text-white"
                      value={newStadiumSize}
                      onChange={(e) => setNewStadiumSize(e.target.value as StadiumSize)}
                    >
                      {Object.values(StadiumSize).map(s => <option key={s} value={s}>{s} Size</option>)}
                    </select>
                  </div>
                  <button 
                    type="submit"
                    disabled={!newStadiumName}
                    className="w-full bg-pitch-600 disabled:bg-gray-300 disabled:cursor-not-allowed hover:bg-pitch-500 text-white font-bold py-2 rounded-lg flex items-center justify-center gap-2 transition-colors"
                  >
                    <Plus size={20} /> Add Stadium
                  </button>
               </form>
            </div>

            <div>
               <h4 className="font-medium text-gray-500 dark:text-gray-400 mb-3 text-sm uppercase tracking-wider">Existing Venues</h4>
               <div className="space-y-2 max-h-64 overflow-y-auto">
                  {stadiums.length === 0 && <div className="text-gray-400 text-sm italic">No stadiums added.</div>}
                  {stadiums.map(stadium => (
                     <div key={stadium.id} className="flex items-center justify-between p-3 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-gray-100 dark:border-gray-700 group">
                        <div>
                           <div className="font-bold dark:text-white">{stadium.name}</div>
                           <div className="text-xs text-gray-500">{stadium.size}</div>
                        </div>
                        <button 
                           onClick={() => handleDeleteStadium(stadium.id)}
                           className="text-gray-400 hover:text-red-500 p-2 rounded-full hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                        >
                           <Trash2 size={16} />
                        </button>
                     </div>
                  ))}
               </div>
            </div>
         </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">

        {/* Match Type Multipliers */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <h3 className="font-bold text-xl mb-6 dark:text-white border-b dark:border-gray-700 pb-2">Match Multipliers</h3>
            <div className="space-y-4">
                {Object.values(MatchType).map((type) => (
                    <div key={type} className="flex justify-between items-center">
                        <label className="text-gray-600 dark:text-gray-300 font-medium">
                            {type.replace('_', ' ')}
                        </label>
                        <input 
                            type="number" step="0.1"
                            value={localSettings.matchTypeWeights[type]}
                            onChange={(e) => updateMatchTypeWeight(type, e.target.value)}
                            className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                        />
                    </div>
                ))}
            </div>

            <h3 className="font-bold text-xl mt-8 mb-6 dark:text-white border-b dark:border-gray-700 pb-2">Stadium Multipliers</h3>
            <div className="space-y-4">
                {Object.values(StadiumSize).map((size) => (
                    <div key={size} className="flex justify-between items-center">
                        <label className="text-gray-600 dark:text-gray-300 font-medium">
                            {size} Pitch
                        </label>
                        <input 
                            type="number" step="0.1"
                            value={localSettings.stadiumSizeWeights[size]}
                            onChange={(e) => updateStadiumWeight(size, e.target.value)}
                            className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                        />
                    </div>
                ))}
            </div>
        </div>

        {/* Base Points */}
        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <h3 className="font-bold text-xl mb-6 dark:text-white border-b dark:border-gray-700 pb-2">Base Points</h3>
            <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <label className="text-gray-600 dark:text-gray-300 font-medium">Goal Scored</label>
                    <input 
                        type="number"
                        value={localSettings.basePoints.GOAL}
                        onChange={(e) => updateBasePoint('GOAL', e.target.value)}
                        className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                    />
                </div>
                <div className="flex justify-between items-center">
                    <label className="text-gray-600 dark:text-gray-300 font-medium">Assist</label>
                    <input 
                        type="number"
                        value={localSettings.basePoints.ASSIST}
                        onChange={(e) => updateBasePoint('ASSIST', e.target.value)}
                        className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                    />
                </div>
                <div className="flex justify-between items-center">
                    <label className="text-gray-600 dark:text-gray-300 font-medium">Own Goal Penalty</label>
                    <input 
                        type="number"
                        value={localSettings.basePoints.OWN_GOAL}
                        onChange={(e) => updateBasePoint('OWN_GOAL', e.target.value)}
                        className="w-24 p-2 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-900 rounded-lg text-right font-mono text-red-700 dark:text-red-400 focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                    />
                </div>
                <div className="flex justify-between items-center">
                    <label className="text-gray-600 dark:text-gray-300 font-medium">Clean Sheet (GK)</label>
                    <input 
                        type="number"
                        value={localSettings.basePoints.CLEAN_SHEET}
                        onChange={(e) => updateBasePoint('CLEAN_SHEET', e.target.value)}
                        className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                    />
                </div>
                <div className="flex justify-between items-center">
                    <label className="text-gray-600 dark:text-gray-300 font-medium">Win Bonus</label>
                    <input 
                        type="number"
                        value={localSettings.basePoints.WIN}
                        onChange={(e) => updateBasePoint('WIN', e.target.value)}
                        className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                    />
                </div>
                <div className="flex justify-between items-center">
                    <label className="text-gray-600 dark:text-gray-300 font-medium">Draw Bonus</label>
                    <input 
                        type="number"
                        value={localSettings.basePoints.DRAW}
                        onChange={(e) => updateBasePoint('DRAW', e.target.value)}
                        className="w-24 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none transition-all"
                    />
                </div>
            </div>

            <div className="mt-8 p-4 bg-blue-50 dark:bg-blue-900/30 rounded-lg">
                <p className="text-sm text-blue-700 dark:text-blue-300">
                    <strong>Note:</strong> Total Rating = (Sum of Base Points) × Match Multiplier × Stadium Multiplier
                </p>
            </div>
        </div>
      </div>

      <div className="flex justify-end pt-4">
          <button 
            onClick={handleSave}
            className="bg-pitch-600 hover:bg-pitch-500 text-white px-8 py-4 rounded-xl font-bold text-lg shadow-xl flex items-center gap-3 transition-transform hover:scale-105"
          >
            <Save size={24} />
            Save Configuration
          </button>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Match, MatchType } from '../types';
import { Calendar, MapPin, Trophy, ChevronDown, ChevronUp, User, X, Trash2 } from 'lucide-react';

const MatchHistory: React.FC = () => {
  const { matches, players } = useApp();
  const [expandedMatchId, setExpandedMatchId] = useState<string | null>(null);

  const toggleExpand = (id: string) => {
    setExpandedMatchId(expandedMatchId === id ? null : id);
  };

  const getResultColor = (scoreA: number, scoreB: number, isTeamA: boolean) => {
    if (scoreA === scoreB) return 'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-300';
    if (isTeamA) {
      return scoreA > scoreB 
        ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400' 
        : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400';
    } else {
       return scoreB > scoreA
        ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400' 
        : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400';
    }
  };

  const formatDate = (isoString: string) => {
    return new Date(isoString).toLocaleDateString(undefined, {
      weekday: 'short',
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (matches.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-96 text-gray-400 animate-fade-in">
        <div className="bg-gray-100 dark:bg-gray-800 p-6 rounded-full mb-4">
          <Calendar size={48} />
        </div>
        <h3 className="text-xl font-bold dark:text-white">No Matches Recorded</h3>
        <p className="mt-2 text-center max-w-sm">Go to the "New Match" tab to track your first game!</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
        <Trophy className="text-pitch-600" /> Match History
      </h2>

      <div className="space-y-4">
        {matches.map((match) => {
          const isExpanded = expandedMatchId === match.id;
          const winner = match.scoreA > match.scoreB ? 'A' : match.scoreB > match.scoreA ? 'B' : 'Draw';

          return (
            <div key={match.id} className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden transition-all duration-300">
              {/* Match Header Summary */}
              <div 
                onClick={() => toggleExpand(match.id)}
                className="p-6 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
              >
                <div className="flex flex-col md:flex-row justify-between items-center gap-4">

                  {/* Date & Info */}
                  <div className="flex-1 text-center md:text-left">
                    <div className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-1">
                      {formatDate(match.date)}
                    </div>
                    <div className="flex items-center justify-center md:justify-start gap-2 text-sm text-gray-600 dark:text-gray-300">
                      <span className="bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded text-xs font-bold">
                        {match.type === MatchType.INTERNAL_FRIENDLY ? 'Friendly' : 'Challenger'}
                      </span>
                      <span className="flex items-center gap-1">
                         <MapPin size={12} /> {match.stadiumName || match.stadium}
                      </span>
                    </div>
                  </div>

                  {/* Scoreboard */}
                  <div className="flex items-center gap-6">
                    <div className={`text-right ${winner === 'A' ? 'font-bold text-gray-900 dark:text-white' : 'text-gray-500'}`}>
                      <div className="text-lg md:text-xl">{match.teamAName}</div>
                    </div>
                    <div className="flex items-center bg-gray-100 dark:bg-gray-900 rounded-lg px-4 py-2 gap-3">
                      <span className={`text-2xl md:text-3xl font-bold ${match.scoreA > match.scoreB ? 'text-pitch-600' : 'text-gray-700 dark:text-gray-300'}`}>
                        {match.scoreA}
                      </span>
                      <span className="text-gray-400">-</span>
                      <span className={`text-2xl md:text-3xl font-bold ${match.scoreB > match.scoreA ? 'text-pitch-600' : 'text-gray-700 dark:text-gray-300'}`}>
                        {match.scoreB}
                      </span>
                    </div>
                    <div className={`text-left ${winner === 'B' ? 'font-bold text-gray-900 dark:text-white' : 'text-gray-500'}`}>
                      <div className="text-lg md:text-xl">{match.teamBName}</div>
                    </div>
                  </div>

                  {/* Expand Icon */}
                  <div className="hidden md:block text-gray-400">
                    {isExpanded ? <ChevronUp size={24} /> : <ChevronDown size={24} />}
                  </div>
                </div>
              </div>

              {/* Expanded Details */}
              {isExpanded && (
                <div className="border-t border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-900/30 p-6 animate-slide-down">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    {/* Team A Stats */}
                    <div>
                      <h4 className="font-bold text-gray-500 dark:text-gray-400 mb-3 uppercase text-sm border-b dark:border-gray-700 pb-2 flex justify-between">
                         <span>{match.teamAName} Squad</span>
                         {winner === 'A' && <Trophy size={16} className="text-yellow-500" />}
                      </h4>
                      <div className="space-y-2">
                        {match.players.filter(p => p.team === 'A').map(mp => {
                          const player = players.find(p => p.id === mp.playerId);
                          return (
                            <div key={mp.playerId} className="flex items-center justify-between p-2 rounded bg-white dark:bg-gray-800 shadow-sm">
                               <div className="flex items-center gap-2">
                                  {player?.avatarUrl ? (
                                     <img src={player.avatarUrl} className="w-8 h-8 rounded-full" />
                                  ) : <User className="w-8 h-8 p-1 bg-gray-100 rounded-full" />}
                                  <div>
                                    <div className="text-sm font-bold dark:text-gray-200">{player?.name || 'Unknown'}</div>
                                    <div className="text-xs text-gray-400">{mp.isGK ? 'GK' : player?.position}</div>
                                  </div>
                               </div>
                               <div className="flex gap-2 text-xs">
                                  {mp.goals > 0 && (
                                    <span className="bg-green-100 text-green-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.goals} G
                                    </span>
                                  )}
                                  {mp.assists > 0 && (
                                    <span className="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.assists} A
                                    </span>
                                  )}
                                  {mp.ownGoals > 0 && (
                                    <span className="bg-red-100 text-red-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.ownGoals} OG
                                    </span>
                                  )}
                                  {mp.cleanSheet && (
                                    <span className="bg-yellow-100 text-yellow-700 px-1.5 py-0.5 rounded font-bold">
                                      CS
                                    </span>
                                  )}
                               </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>

                    {/* Team B Stats */}
                    <div>
                      <h4 className="font-bold text-gray-500 dark:text-gray-400 mb-3 uppercase text-sm border-b dark:border-gray-700 pb-2 flex justify-between">
                         <span>{match.teamBName} Squad</span>
                         {winner === 'B' && <Trophy size={16} className="text-yellow-500" />}
                      </h4>
                      <div className="space-y-2">
                        {match.players.filter(p => p.team === 'B').map(mp => {
                          const player = players.find(p => p.id === mp.playerId);
                          return (
                            <div key={mp.playerId} className="flex items-center justify-between p-2 rounded bg-white dark:bg-gray-800 shadow-sm">
                               <div className="flex items-center gap-2">
                                  {player?.avatarUrl ? (
                                     <img src={player.avatarUrl} className="w-8 h-8 rounded-full" />
                                  ) : <User className="w-8 h-8 p-1 bg-gray-100 rounded-full" />}
                                  <div>
                                    <div className="text-sm font-bold dark:text-gray-200">{player?.name || 'Unknown'}</div>
                                    <div className="text-xs text-gray-400">{mp.isGK ? 'GK' : player?.position}</div>
                                  </div>
                               </div>
                               <div className="flex gap-2 text-xs">
                                  {mp.goals > 0 && (
                                    <span className="bg-green-100 text-green-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.goals} G
                                    </span>
                                  )}
                                  {mp.assists > 0 && (
                                    <span className="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.assists} A
                                    </span>
                                  )}
                                  {mp.ownGoals > 0 && (
                                    <span className="bg-red-100 text-red-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.ownGoals} OG
                                    </span>
                                  )}
                                  {mp.cleanSheet && (
                                    <span className="bg-yellow-100 text-yellow-700 px-1.5 py-0.5 rounded font-bold">
                                      CS
                                    </span>
                                  )}
                               </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default MatchHistory;

export enum MatchType {
  INTERNAL_FRIENDLY = 'INTERNAL_FRIENDLY',
  CHALLENGER = 'CHALLENGER',
}

export enum StadiumSize {
  SMALL = 'SMALL', // e.g. 5-a-side
  MEDIUM = 'MEDIUM', // e.g. 7-a-side
  LARGE = 'LARGE', // e.g. 11-a-side
}

export enum Position {
  FW = 'Forward',
  MF = 'Midfielder',
  DF = 'Defender',
  GK = 'Goalkeeper',
}

export interface Stadium {
  id: string;
  name: string;
  size: StadiumSize;
}

export interface PlayerStats {
  goals: number;
  assists: number;
  ownGoals: number; // New stat
  cleanSheets: number; // Only relevant if played as GK
  wins: number;
  draws: number;
  losses: number;
  matchesPlayed: number;
  weightedRating: number;
}

export interface Player {
  id: string;
  name: string;
  position: Position;
  avatarUrl?: string;
  isExternal?: boolean; // For ringing players
}

export interface MatchPlayerStats {
  playerId: string;
  team: 'A' | 'B';
  goals: number;
  assists: number;
  ownGoals: number; // New stat
  isGK: boolean;
  cleanSheet: boolean;
}

export interface Match {
  id: string;
  date: string;
  type: MatchType;
  stadium: StadiumSize;
  stadiumName?: string; // Optional name of the venue
  youtubeLink?: string; // Optional video link
  teamAName: string;
  teamBName: string;
  scoreA: number;
  scoreB: number;
  players: MatchPlayerStats[]; // Records who played in this match and their performance
}

export interface SynergyPair {
  player1Id: string;
  player2Id: string;
  matchesTogether: number;
  winsTogether: number;
  winRate: number;
}

export interface AppSettings {
  matchTypeWeights: Record<MatchType, number>;
  stadiumSizeWeights: Record<StadiumSize, number>;
  basePoints: {
    GOAL: number;
    ASSIST: number;
    OWN_GOAL: number; // New weighting
    CLEAN_SHEET: number;
    WIN: number;
    DRAW: number;
  };
}

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { Player, Match, MatchType, StadiumSize, Position, PlayerStats, SynergyPair, AppSettings, Stadium } from '../types';
import { MATCH_TYPE_WEIGHTS, STADIUM_SIZE_WEIGHTS, BASE_POINTS } from '../constants';

interface AppContextType {
  players: Player[];
  matches: Match[];
  stadiums: Stadium[];
  settings: AppSettings;
  matchToEdit: Match | null; // For passing data to MatchManager
  setMatchToEdit: (match: Match | null) => void;
  addPlayer: (player: Player) => void;
  deletePlayer: (id: string) => void;
  updatePlayerAvatar: (id: string, url: string) => void;
  addMatch: (match: Match) => void;
  updateMatch: (updatedMatch: Match) => void;
  importMatches: (matches: Match[]) => void;
  addStadium: (stadium: Stadium) => void;
  deleteStadium: (id: string) => void;
  updateSettings: (newSettings: AppSettings) => void;
  getPlayerStats: (playerId: string) => PlayerStats;
  getAllPlayerStats: () => (Player & PlayerStats)[];
  getBestSynergy: () => SynergyPair[];
}

const AppContext = createContext<AppContextType | undefined>(undefined);

// Initial Mock Data
const INITIAL_PLAYERS: Player[] = [
  { id: '1', name: 'Tsubasa', position: Position.MF, avatarUrl: 'https://picsum.photos/100/100?random=1' },
  { id: '2', name: 'Hyuga', position: Position.FW, avatarUrl: 'https://picsum.photos/100/100?random=2' },
  { id: '3', name: 'Wakabayashi', position: Position.GK, avatarUrl: 'https://picsum.photos/100/100?random=3' },
  { id: '4', name: 'Misaki', position: Position.MF, avatarUrl: 'https://picsum.photos/100/100?random=4' },
];

const INITIAL_STADIUMS: Stadium[] = [
  { id: '1', name: 'Community Center Field', size: StadiumSize.SMALL },
  { id: '2', name: 'Riverside Park', size: StadiumSize.MEDIUM },
  { id: '3', name: 'City Stadium', size: StadiumSize.LARGE },
];

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [players, setPlayers] = useState<Player[]>(INITIAL_PLAYERS);
  const [matches, setMatches] = useState<Match[]>([]);
  const [stadiums, setStadiums] = useState<Stadium[]>(INITIAL_STADIUMS);
  const [matchToEdit, setMatchToEdit] = useState<Match | null>(null);
  const [settings, setSettings] = useState<AppSettings>({
    matchTypeWeights: { ...MATCH_TYPE_WEIGHTS },
    stadiumSizeWeights: { ...STADIUM_SIZE_WEIGHTS },
    basePoints: { ...BASE_POINTS }
  });

  const addPlayer = (player: Player) => {
    setPlayers(prev => [...prev, player]);
  };

  const deletePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const updatePlayerAvatar = (id: string, url: string) => {
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, avatarUrl: url } : p));
  };

  const addMatch = (match: Match) => {
    setMatches(prev => [match, ...prev]); // Newest first
  };

  const updateMatch = (updatedMatch: Match) => {
    setMatches(prev => prev.map(m => m.id === updatedMatch.id ? updatedMatch : m));
  };

  const importMatches = (newMatches: Match[]) => {
      // Avoid duplicates based on ID
      const existingIds = new Set(matches.map(m => m.id));
      const uniqueNewMatches = newMatches.filter(m => !existingIds.has(m.id));
      setMatches(prev => [...uniqueNewMatches, ...prev]);
  };

  const addStadium = (stadium: Stadium) => {
    setStadiums(prev => [...prev, stadium]);
  };

  const deleteStadium = (id: string) => {
    setStadiums(prev => prev.filter(s => s.id !== id));
  };

  const updateSettings = (newSettings: AppSettings) => {
    setSettings(newSettings);
  };

  const getPlayerStats = (playerId: string): PlayerStats => {
    const stats: PlayerStats = {
      goals: 0,
      assists: 0,
      ownGoals: 0,
      cleanSheets: 0,
      wins: 0,
      draws: 0,
      losses: 0,
      matchesPlayed: 0,
      weightedRating: 0,
    };

    matches.forEach(match => {
      const pMatch = match.players.find(p => p.playerId === playerId);
      if (!pMatch) return;

      stats.matchesPlayed += 1;
      stats.goals += pMatch.goals;
      stats.assists += pMatch.assists;
      stats.ownGoals += (pMatch.ownGoals || 0); // Safety check for old data
      if (pMatch.isGK && pMatch.cleanSheet) stats.cleanSheets += 1;

      // Result
      const isTeamA = pMatch.team === 'A';
      const myScore = isTeamA ? match.scoreA : match.scoreB;
      const oppScore = isTeamA ? match.scoreB : match.scoreA;

      if (myScore > oppScore) stats.wins += 1;
      else if (myScore === oppScore) stats.draws += 1;
      else stats.losses += 1;

      // Weighted Rating Calculation
      const matchMultiplier = settings.matchTypeWeights[match.type] * settings.stadiumSizeWeights[match.stadium];

      let matchRating = 0;
      matchRating += pMatch.goals * settings.basePoints.GOAL;
      matchRating += pMatch.assists * settings.basePoints.ASSIST;
      matchRating += (pMatch.ownGoals || 0) * (settings.basePoints.OWN_GOAL || -3); // Deduct for OGs

      if (pMatch.isGK && pMatch.cleanSheet) matchRating += settings.basePoints.CLEAN_SHEET;

      if (myScore > oppScore) matchRating += settings.basePoints.WIN;
      else if (myScore === oppScore) matchRating += settings.basePoints.DRAW;

      stats.weightedRating += (matchRating * matchMultiplier);
    });

    return stats;
  };

  const getAllPlayerStats = () => {
    return players.map(p => ({
      ...p,
      ...getPlayerStats(p.id)
    }));
  };

  // O(N^2 * M) complexity - acceptable for small teams (e.g. < 50 players, < 100 matches)
  const getBestSynergy = (): SynergyPair[] => {
    const pairs: Map<string, SynergyPair> = new Map();

    matches.forEach(match => {
      // Group players by team for this match
      const teamA = match.players.filter(p => p.team === 'A');
      const teamB = match.players.filter(p => p.team === 'B');

      const processTeam = (teamMembers: typeof teamA, isWin: boolean) => {
        for (let i = 0; i < teamMembers.length; i++) {
          for (let j = i + 1; j < teamMembers.length; j++) {
            const p1 = teamMembers[i].playerId;
            const p2 = teamMembers[j].playerId;
            // Create a consistent key regardless of order
            const key = [p1, p2].sort().join('_');

            if (!pairs.has(key)) {
              pairs.set(key, { 
                player1Id: p1 < p2 ? p1 : p2, 
                player2Id: p1 < p2 ? p2 : p1, 
                matchesTogether: 0, 
                winsTogether: 0, 
                winRate: 0 
              });
            }

            const current = pairs.get(key)!;
            current.matchesTogether += 1;
            if (isWin) current.winsTogether += 1;
          }
        }
      };

      const winA = match.scoreA > match.scoreB;
      const winB = match.scoreB > match.scoreA;

      processTeam(teamA, winA);
      processTeam(teamB, winB);
    });

    return Array.from(pairs.values())
      .map(pair => ({ ...pair, winRate: pair.matchesTogether > 0 ? (pair.winsTogether / pair.matchesTogether) * 100 : 0 }))
      .filter(pair => pair.matchesTogether >= 2) // Minimum matches together threshold
      .sort((a, b) => b.winRate - a.winRate);
  };

  return (
    <AppContext.Provider value={{ 
      players, 
      matches, 
      stadiums,
      settings,
      matchToEdit,
      setMatchToEdit,
      addPlayer, 
      deletePlayer,
      updatePlayerAvatar,
      addMatch, 
      updateMatch,
      importMatches,
      addStadium,
      deleteStadium,
      updateSettings,
      getPlayerStats,
      getAllPlayerStats,
      getBestSynergy
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { Match, MatchType, StadiumSize, MatchPlayerStats, Position } from '../types';
import { Save, Search, Calendar, Clock, LayoutGrid, List, PlusCircle, MinusCircle, HelpCircle, Youtube, Edit2 } from 'lucide-react';
import { useToast } from '../context/ToastContext';

const MatchManager: React.FC = () => {
  const { players, addMatch, updateMatch, stadiums, matchToEdit, setMatchToEdit } = useApp();
  const { showToast } = useToast();

  const [step, setStep] = useState<1 | 2>(1); // 1: Setup, 2: Stats

  // Date & Time
  const [matchDate, setMatchDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [matchTime, setMatchTime] = useState(() => new Date().toTimeString().split(' ')[0].slice(0, 5));

  // Setup State
  const [matchType, setMatchType] = useState<MatchType>(MatchType.INTERNAL_FRIENDLY);
  const [youtubeLink, setYoutubeLink] = useState('');

  // Venue State
  const [selectedStadiumId, setSelectedStadiumId] = useState<string>('custom');
  const [customStadiumName, setCustomStadiumName] = useState('');
  const [stadiumSize, setStadiumSize] = useState<StadiumSize>(StadiumSize.MEDIUM);

  const [teamAName, setTeamAName] = useState('Team A');
  const [teamBName, setTeamBName] = useState('Team B');
  const [selectedPlayers, setSelectedPlayers] = useState<{ id: string, team: 'A' | 'B' }[]>([]);

  // Search State for Squad Selection
  const [squadSearch, setSquadSearch] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // Stats State
  // otherGoals stores goals that are NOT attributed to specific players (e.g. ringers, or generic own goals not attributed to an opponent player)
  const [otherGoalsA, setOtherGoalsA] = useState(0);
  const [otherGoalsB, setOtherGoalsB] = useState(0);
  const [playerPerformances, setPlayerPerformances] = useState<Record<string, { goals: number, assists: number, ownGoals: number, isGK: boolean, cleanSheet: boolean }>>({});

  // Effect to load match data if we are in Edit Mode
  useEffect(() => {
    if (matchToEdit) {
      // 1. Parse Date/Time
      const dateObj = new Date(matchToEdit.date);
      setMatchDate(dateObj.toISOString().split('T')[0]);
      setMatchTime(dateObj.toTimeString().split(' ')[0].slice(0, 5));

      // 2. Setup Logistics
      setMatchType(matchToEdit.type);
      setYoutubeLink(matchToEdit.youtubeLink || '');
      setTeamAName(matchToEdit.teamAName);
      setTeamBName(matchToEdit.teamBName);

      // 3. Stadium Logic
      const existingStadium = stadiums.find(s => s.name === matchToEdit.stadiumName && s.size === matchToEdit.stadium);
      if (existingStadium) {
        setSelectedStadiumId(existingStadium.id);
        setStadiumSize(existingStadium.size);
      } else {
        setSelectedStadiumId('custom');
        setCustomStadiumName(matchToEdit.stadiumName || '');
        setStadiumSize(matchToEdit.stadium);
      }

      // 4. Players & Performances
      const selection: { id: string, team: 'A' | 'B' }[] = [];
      const perfs: typeof playerPerformances = {};

      let calculatedScoreA = 0;
      let calculatedScoreB = 0;

      matchToEdit.players.forEach(mp => {
        selection.push({ id: mp.playerId, team: mp.team });
        perfs[mp.playerId] = {
          goals: mp.goals,
          assists: mp.assists,
          ownGoals: mp.ownGoals || 0,
          isGK: mp.isGK,
          cleanSheet: mp.cleanSheet
        };

        if (mp.team === 'A') {
            calculatedScoreA += mp.goals;
            calculatedScoreB += (mp.ownGoals || 0); // Own goals count for opponent
        } else {
            calculatedScoreB += mp.goals;
            calculatedScoreA += (mp.ownGoals || 0);
        }
      });

      setSelectedPlayers(selection);
      setPlayerPerformances(perfs);

      // 5. Calculate "Other Goals" by subtracting player contributions from total score
      setOtherGoalsA(Math.max(0, matchToEdit.scoreA - calculatedScoreA));
      setOtherGoalsB(Math.max(0, matchToEdit.scoreB - calculatedScoreB));

    } else {
      // Reset logic is handled by clearForm, but helpful to ensure defaults on mount if needed
    }
  }, [matchToEdit, stadiums]);

  const clearForm = () => {
    setMatchToEdit(null);
    setStep(1);
    setMatchDate(new Date().toISOString().split('T')[0]);
    setMatchTime(new Date().toTimeString().split(' ')[0].slice(0, 5));
    setMatchType(MatchType.INTERNAL_FRIENDLY);
    setYoutubeLink('');
    setSelectedStadiumId('custom');
    setCustomStadiumName('');
    setStadiumSize(StadiumSize.MEDIUM);
    setTeamAName('Team A');
    setTeamBName('Team B');
    setSelectedPlayers([]);
    setOtherGoalsA(0);
    setOtherGoalsB(0);
    setPlayerPerformances({});
  };

  const handleCancel = () => {
    if (step === 2) {
        setStep(1);
    } else {
        clearForm();
    }
  };

  const teamAPlayers = selectedPlayers.filter(p => p.team === 'A');
  const teamBPlayers = selectedPlayers.filter(p => p.team === 'B');

  // Computed Scores
  const teamAGoalsFromPlayers = teamAPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.goals || 0), 0);
  const teamBOwnGoals = teamBPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.ownGoals || 0), 0);

  const teamBGoalsFromPlayers = teamBPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.goals || 0), 0);
  const teamAOwnGoals = teamAPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.ownGoals || 0), 0);

  const totalScoreA = teamAGoalsFromPlayers + teamBOwnGoals + otherGoalsA;
  const totalScoreB = teamBGoalsFromPlayers + teamAOwnGoals + otherGoalsB;

  const handleVenueChange = (val: string) => {
    setSelectedStadiumId(val);
    if (val !== 'custom') {
      const stadium = stadiums.find(s => s.id === val);
      if (stadium) {
        setStadiumSize(stadium.size);
      }
    } else {
        setCustomStadiumName('');
    }
  };

  const getEffectiveStadiumName = () => {
     if (selectedStadiumId === 'custom') return customStadiumName || 'Unknown Venue';
     const stadium = stadiums.find(s => s.id === selectedStadiumId);
     return stadium ? stadium.name : 'Unknown Venue';
  };

  const togglePlayerSelection = (playerId: string, team: 'A' | 'B') => {
    setSelectedPlayers(prev => {
      const exists = prev.find(p => p.id === playerId);
      if (exists) {
        if (exists.team === team) {
          // Deselect
          return prev.filter(p => p.id !== playerId);
        } else {
          // Switch team
          return prev.map(p => p.id === playerId ? { ...p, team } : p);
        }
      } else {
        // Add
        return [...prev, { id: playerId, team }];
      }
    });
  };

  const initializePerformance = () => {
    // If not editing, or if new players were added, ensure they have performance objects
    const perfs: typeof playerPerformances = { ...playerPerformances };
    selectedPlayers.forEach(p => {
      if (!perfs[p.id]) {
          perfs[p.id] = { goals: 0, assists: 0, ownGoals: 0, isGK: false, cleanSheet: false };
      }
    });
    setPlayerPerformances(perfs);

    // If we are editing, we keep the existing Other Goals, otherwise reset? 
    // Actually, if editing, useEffect set them. If new match, they are 0.
    setStep(2);
  };

  const updateStat = (playerId: string, field: keyof typeof playerPerformances[string], value: any) => {
    setPlayerPerformances(prev => ({
      ...prev,
      [playerId]: { ...prev[playerId], [field]: value }
    }));
  };

  const handleFinishMatch = () => {
    const combinedDate = new Date(`${matchDate}T${matchTime}`);

    const matchPlayers: MatchPlayerStats[] = selectedPlayers.map(sp => ({
      playerId: sp.id,
      team: sp.team,
      ...playerPerformances[sp.id]
    }));

    const matchData: Match = {
      id: matchToEdit ? matchToEdit.id : Date.now().toString(),
      date: combinedDate.toISOString(),
      type: matchType,
      stadium: stadiumSize,
      stadiumName: getEffectiveStadiumName(),
      youtubeLink: youtubeLink.trim() || undefined,
      teamAName,
      teamBName,
      scoreA: totalScoreA,
      scoreB: totalScoreB,
      players: matchPlayers
    };

    if (matchToEdit) {
        updateMatch(matchData);
        showToast("Match updated successfully!", "success");
    } else {
        addMatch(matchData);
        showToast("Match saved successfully!", "success");
    }

    clearForm();
  };

  const filteredSquadList = players.filter(p => p.name.toLowerCase().includes(squadSearch.toLowerCase()));

  const positionColor = (pos: Position) => {
    switch (pos) {
        case Position.GK: return 'bg-yellow-100 text-yellow-800 border-yellow-200';
        case Position.DF: return 'bg-blue-100 text-blue-800 border-blue-200';
        case Position.MF: return 'bg-emerald-100 text-emerald-800 border-emerald-200';
        case Position.FW: return 'bg-red-100 text-red-800 border-red-200';
        default: return 'bg-gray-100';
    }
  };

  if (step === 1) {
    return (
      <div className="space-y-8 animate-fade-in pb-12">
        <div className="flex justify-between items-center">
            <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
                {matchToEdit ? <><Edit2 className="text-pitch-600"/> Edit Match</> : 'New Match Setup'}
            </h2>
            {matchToEdit && (
                <button onClick={clearForm} className="text-red-500 hover:text-red-600 text-sm font-medium">Cancel Edit</button>
            )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <h3 className="font-bold mb-4 dark:text-gray-200 flex items-center gap-2">Match Logistics</h3>
            <div className="space-y-4">

              {/* Date and Time */}
              <div className="flex gap-4">
                 <div className="flex-1">
                    <label className="block text-sm text-gray-500 mb-1 flex items-center gap-1">
                        <Calendar size={14} /> Date
                    </label>
                    <input 
                       type="date"
                       className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                       value={matchDate}
                       onChange={(e) => setMatchDate(e.target.value)}
                    />
                 </div>
                 <div className="w-1/3">
                    <label className="block text-sm text-gray-500 mb-1 flex items-center gap-1">
                        <Clock size={14} /> Time
                    </label>
                    <input 
                       type="time"
                       className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                       value={matchTime}
                       onChange={(e) => setMatchTime(e.target.value)}
                    />
                 </div>
              </div>

              <div>
                <label className="block text-sm text-gray-500 mb-1">Type</label>
                <select 
                  className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                  value={matchType} onChange={(e) => setMatchType(e.target.value as MatchType)}>
                  {Object.values(MatchType).map(t => <option key={t} value={t}>{t.replace('_', ' ')}</option>)}
                </select>
              </div>

              {/* Stadium Selection */}
              <div>
                <label className="block text-sm text-gray-500 mb-1">Stadium</label>
                <select 
                  className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white mb-2"
                  value={selectedStadiumId} onChange={(e) => handleVenueChange(e.target.value)}>
                   {stadiums.map(s => <option key={s.id} value={s.id}>{s.name} ({s.size})</option>)}
                   <option value="custom">-- Custom Venue --</option>
                </select>

                {selectedStadiumId === 'custom' ? (
                   <div className="flex gap-2 animate-fade-in">
                      <input 
                        type="text" 
                        placeholder="Venue Name"
                        className="flex-1 p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                        value={customStadiumName}
                        onChange={(e) => setCustomStadiumName(e.target.value)}
                      />
                      <select 
                        className="w-32 p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                        value={stadiumSize} onChange={(e) => setStadiumSize(e.target.value as StadiumSize)}>
                        {Object.values(StadiumSize).map(t => <option key={t} value={t}>{t}</option>)}
                      </select>
                   </div>
                ) : (
                    <div className="text-sm text-gray-400 pl-1">
                        Applied Size: <span className="font-semibold text-pitch-600 dark:text-pitch-400">{stadiumSize}</span>
                    </div>
                )}
              </div>

              {/* YouTube Link */}
              <div>
                 <label className="block text-sm text-gray-500 mb-1 flex items-center gap-1">
                    <Youtube size={14} /> YouTube Link (Optional)
                 </label>
                 <input 
                    type="url" 
                    placeholder="https://youtu.be/..."
                    className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                    value={youtubeLink}
                    onChange={(e) => setYoutubeLink(e.target.value)}
                 />
              </div>

              <div className="flex gap-4">
                <div className="flex-1">
                   <label className="block text-sm text-gray-500 mb-1">Team A Name</label>
                   <input className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white" value={teamAName} onChange={e => setTeamAName(e.target.value)} />
                </div>
                <div className="flex-1">
                   <label className="block text-sm text-gray-500 mb-1">Team B Name</label>
                   <input className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white" value={teamBName} onChange={e => setTeamBName(e.target.value)} />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col justify-between">
             <div>
                <h3 className="font-bold mb-4 dark:text-gray-200">Summary</h3>
                <div className="flex justify-between items-center bg-gray-50 dark:bg-gray-900 p-4 rounded-lg mb-4">
                    <div className="text-center">
                        <div className="text-2xl font-bold text-pitch-600">{teamAPlayers.length}</div>
                        <div className="text-xs text-gray-500">{teamAName}</div>
                    </div>
                    <div className="text-gray-400 font-light">vs</div>
                    <div className="text-center">
                        <div className="text-2xl font-bold text-pitch-600">{teamBPlayers.length}</div>
                        <div className="text-xs text-gray-500">{teamBName}</div>
                    </div>
                </div>
                <div className="space-y-2 text-sm text-gray-600 dark:text-gray-400">
                    <div className="flex justify-between border-b dark:border-gray-700 pb-1">
                        <span>Date:</span>
                        <span className="font-medium dark:text-white">{matchDate} {matchTime}</span>
                    </div>
                    <div className="flex justify-between border-b dark:border-gray-700 pb-1">
                        <span>Venue:</span>
                        <span className="font-medium dark:text-white">{getEffectiveStadiumName()}</span>
                    </div>
                    <div className="flex justify-between">
                        <span>Type:</span>
                        <span className="font-medium dark:text-white">{matchType.replace('_', ' ')}</span>
                    </div>
                </div>
             </div>
             <button 
                disabled={selectedPlayers.length === 0}
                onClick={initializePerformance}
                className="w-full mt-6 py-3 bg-pitch-600 disabled:bg-gray-400 text-white rounded-xl font-bold hover:bg-pitch-500 transition-colors shadow-lg disabled:shadow-none"
             >
                {matchToEdit ? 'Continue to Stats' : 'Start Match Tracking'}
             </button>
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
           <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
               <h3 className="font-bold dark:text-gray-200">Squad Selection</h3>

               <div className="flex gap-2 w-full sm:w-auto">
                   <div className="relative flex-1 sm:w-64">
                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Search players..." 
                            value={squadSearch}
                            onChange={(e) => setSquadSearch(e.target.value)}
                            className="w-full pl-9 pr-4 py-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-1 focus:ring-pitch-500 outline-none dark:text-white"
                        />
                   </div>
                   <div className="flex bg-gray-50 dark:bg-gray-900 rounded-lg border border-gray-200 dark:border-gray-700 p-1">
                     <button 
                        onClick={() => setViewMode('grid')}
                        className={`p-1.5 rounded ${viewMode === 'grid' ? 'bg-white dark:bg-gray-700 text-pitch-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                     >
                        <LayoutGrid size={18} />
                     </button>
                     <button 
                        onClick={() => setViewMode('list')}
                        className={`p-1.5 rounded ${viewMode === 'list' ? 'bg-white dark:bg-gray-700 text-pitch-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                     >
                        <List size={18} />
                     </button>
                  </div>
               </div>
           </div>

           <div className="max-h-96 overflow-y-auto pr-2">
              {/* GRID VIEW */}
              {viewMode === 'grid' && (
                  <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                    {filteredSquadList.map(p => {
                        const selection = selectedPlayers.find(sp => sp.id === p.id);
                        return (
                        <div key={p.id} className={`p-3 rounded-lg border flex flex-col items-center gap-2 transition-all ${selection ? 'border-pitch-500 bg-pitch-50 dark:bg-pitch-900/20' : 'border-gray-200 dark:border-gray-700'}`}>
                            <div className="relative">
                                <img src={p.avatarUrl} className="w-12 h-12 rounded-full object-cover" alt={p.name} />
                                <span className={`absolute -bottom-1 -right-1 text-[10px] px-1.5 py-0.5 rounded font-bold uppercase ${positionColor(p.position)}`}>{p.position}</span>
                            </div>
                            <span className="font-medium text-sm dark:text-white truncate w-full text-center">{p.name}</span>
                            <div className="flex gap-2 w-full mt-1">
                                <button 
                                    onClick={() => togglePlayerSelection(p.id, 'A')}
                                    className={`flex-1 text-xs py-1.5 font-medium rounded transition-colors ${selection?.team === 'A' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                                    Team A
                                </button>
                                <button 
                                    onClick={() => togglePlayerSelection(p.id, 'B')}
                                    className={`flex-1 text-xs py-1.5 font-medium rounded transition-colors ${selection?.team === 'B' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                                    Team B
                                </button>
                            </div>
                        </div>
                        )
                    })}
                  </div>
              )}

              {/* LIST VIEW */}
              {viewMode === 'list' && (
                  <div className="space-y-2">
                      {filteredSquadList.map(p => {
                        const selection = selectedPlayers.find(sp => sp.id === p.id);
                        return (
                            <div key={p.id} className={`flex items-center justify-between p-3 rounded-lg border transition-all hover:bg-gray-50 dark:hover:bg-gray-800/50 ${selection ? 'border-pitch-500 bg-pitch-50 dark:bg-pitch-900/20' : 'border-gray-200 dark:border-gray-700'}`}>
                                <div className="flex items-center gap-4">
                                    <img src={p.avatarUrl} className="w-10 h-10 rounded-full object-cover" alt={p.name} />
                                    <div>
                                        <div className="font-bold dark:text-white text-sm">{p.name}</div>
                                        <div className={`text-[10px] inline-block px-1.5 rounded uppercase font-bold mt-0.5 ${positionColor(p.position)}`}>{p.position}</div>
                                    </div>
                                </div>
                                <div className="flex gap-2">
                                     <button 
                                        onClick={() => togglePlayerSelection(p.id, 'A')}
                                        className={`w-20 text-xs py-2 font-medium rounded transition-colors ${selection?.team === 'A' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                                        Team A
                                    </button>
                                    <button 
                                        onClick={() => togglePlayerSelection(p.id, 'B')}
                                        className={`w-20 text-xs py-2 font-medium rounded transition-colors ${selection?.team === 'B' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                                        Team B
                                    </button>
                                </div>
                            </div>
                        )
                      })}
                  </div>
              )}
           </div>

           {filteredSquadList.length === 0 && (
               <div className="text-center py-8 text-gray-400">No players found matching "{squadSearch}"</div>
           )}
        </div>
      </div>
    );
  }

  // Step 2: Stats Input
  return (
    <div className="space-y-6 animate-fade-in pb-12">
       <div className="flex justify-between items-center">
         <h2 className="text-3xl font-bold dark:text-white">{matchToEdit ? 'Edit Results' : 'Match Result'}</h2>
         <button onClick={handleCancel} className="text-gray-500 hover:text-gray-700 dark:hover:text-gray-300">
            {matchToEdit ? 'Cancel Edit' : 'Go Back'}
         </button>
       </div>

       {/* Scoreboard Input */}
       <div className="bg-jersey-dark p-6 sm:p-8 rounded-2xl text-white shadow-lg relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-pitch-500 to-blue-500"></div>

          <div className="flex justify-center items-center gap-4 sm:gap-12 relative z-10">
            {/* Team A Score */}
            <div className="text-center flex-1">
                <h3 className="text-lg sm:text-xl mb-2 text-pitch-400 font-bold truncate">{teamAName}</h3>
                <div className="text-5xl sm:text-7xl font-bold tracking-tight">{totalScoreA}</div>
                <div className="flex items-center justify-center gap-2 mt-2">
                    <span className="text-xs text-gray-400">Other:</span>
                    <div className="flex items-center gap-1 bg-white/10 rounded-lg px-2 py-1">
                        <button onClick={() => setOtherGoalsA(Math.max(0, otherGoalsA - 1))} className="hover:text-pitch-400"><MinusCircle size={14}/></button>
                        <span className="text-sm font-mono w-4 text-center">{otherGoalsA}</span>
                        <button onClick={() => setOtherGoalsA(otherGoalsA + 1)} className="hover:text-pitch-400"><PlusCircle size={14}/></button>
                    </div>
                </div>
            </div>

            <div className="text-3xl sm:text-5xl font-thin text-gray-600">-</div>

            {/* Team B Score */}
            <div className="text-center flex-1">
                <h3 className="text-lg sm:text-xl mb-2 text-blue-400 font-bold truncate">{teamBName}</h3>
                <div className="text-5xl sm:text-7xl font-bold tracking-tight">{totalScoreB}</div>
                <div className="flex items-center justify-center gap-2 mt-2">
                    <span className="text-xs text-gray-400">Other:</span>
                    <div className="flex items-center gap-1 bg-white/10 rounded-lg px-2 py-1">
                        <button onClick={() => setOtherGoalsB(Math.max(0, otherGoalsB - 1))} className="hover:text-pitch-400"><MinusCircle size={14}/></button>
                        <span className="text-sm font-mono w-4 text-center">{otherGoalsB}</span>
                        <button onClick={() => setOtherGoalsB(otherGoalsB + 1)} className="hover:text-pitch-400"><PlusCircle size={14}/></button>
                    </div>
                </div>
            </div>
          </div>

          <div className="text-center mt-6 text-xs text-gray-500 flex justify-center gap-4">
               <span>Date: {matchDate} {matchTime}</span>
               <span>•</span>
               <span>Venue: {getEffectiveStadiumName()}</span>
          </div>
       </div>

       <div className="flex items-center gap-2 text-sm text-gray-500 bg-blue-50 dark:bg-blue-900/20 p-3 rounded-lg border border-blue-100 dark:border-blue-900/30">
          <HelpCircle size={16} className="text-blue-500" />
          <span>Score updates automatically. "Other" tracks goals not attributed to listed players. <strong className="text-pitch-600 dark:text-pitch-400">Own Goals (OG)</strong> count toward the opponent.</span>
       </div>

       {/* Player Stats Input */}
       <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {[
              { team: 'A', name: teamAName, players: teamAPlayers, otherGoals: otherGoalsA, total: totalScoreA }, 
              { team: 'B', name: teamBName, players: teamBPlayers, otherGoals: otherGoalsB, total: totalScoreB }
            ].map((group) => (
            <div key={group.team} className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
               <div className="flex justify-between items-center mb-4 border-b border-gray-100 dark:border-gray-700 pb-2">
                   <h3 className="font-bold text-xl text-pitch-600">{group.name} Stats</h3>
                   <div className="text-sm text-gray-400">Total: <span className="text-gray-900 dark:text-white font-bold">{group.total}</span></div>
               </div>

               <div className="space-y-4">
                  {group.players.map(sp => {
                     const p = players.find(x => x.id === sp.id)!;
                     const stats = playerPerformances[p.id];
                     return (
                        <div key={p.id} className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-900 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors">
                           <img src={p.avatarUrl} className="w-10 h-10 rounded-full bg-white" alt={p.name} />
                           <div className="flex-1 min-w-0">
                             <div className="font-bold truncate dark:text-white text-sm">{p.name}</div>
                             <div className="text-xs text-gray-500">{p.position}</div>
                           </div>

                           {/* Goal Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">Goals</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border rounded dark:bg-gray-800 dark:border-gray-600 dark:text-white focus:border-pitch-500 outline-none"
                                value={stats.goals}
                                onChange={e => updateStat(p.id, 'goals', parseInt(e.target.value))}
                              />
                           </div>

                           {/* Assist Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">Asst</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border rounded dark:bg-gray-800 dark:border-gray-600 dark:text-white focus:border-pitch-500 outline-none"
                                value={stats.assists}
                                onChange={e => updateStat(p.id, 'assists', parseInt(e.target.value))}
                              />
                           </div>

                           {/* Own Goal Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-red-400 mb-0.5 uppercase font-bold" title="Own Goal">OG</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border border-red-200 dark:border-red-900 rounded dark:bg-gray-800 dark:text-white focus:border-red-500 outline-none"
                                value={stats.ownGoals}
                                onChange={e => updateStat(p.id, 'ownGoals', parseInt(e.target.value))}
                              />
                           </div>

                           {/* GK Toggle */}
                           <div className="flex flex-col items-center px-1">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">GK</span>
                              <input 
                                type="checkbox" className="w-5 h-5 accent-pitch-600 rounded cursor-pointer"
                                checked={stats.isGK}
                                onChange={e => updateStat(p.id, 'isGK', e.target.checked)}
                              />
                           </div>

                           {/* Clean Sheet (Only if GK) */}
                           {stats.isGK && (
                             <div className="flex flex-col items-center animate-fade-in px-1">
                                <span className="text-[10px] text-gray-400 mb-0.5 uppercase">CS</span>
                                <input 
                                  type="checkbox" className="w-5 h-5 accent-pitch-600 rounded cursor-pointer"
                                  checked={stats.cleanSheet}
                                  onChange={e => updateStat(p.id, 'cleanSheet', e.target.checked)}
                                />
                             </div>
                           )}
                        </div>
                     )
                  })}
               </div>
            </div>
          ))}
       </div>

       <div className="flex justify-end pt-6">
          <button 
            onClick={handleFinishMatch}
            className="bg-pitch-600 hover:bg-pitch-500 text-white px-8 py-4 rounded-xl font-bold text-lg shadow-xl flex items-center gap-3 transition-transform hover:scale-105"
          >
            <Save size={24} />
            {matchToEdit ? 'Update Match Results' : 'Save Match Results'}
          </button>
       </div>
    </div>
  );
};

export default MatchManager;

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Match, MatchType } from '../types';
import { Calendar, MapPin, Trophy, ChevronDown, ChevronUp, User, Youtube, Edit2 } from 'lucide-react';

interface MatchHistoryProps {
  onEdit?: () => void;
}

const MatchHistory: React.FC<MatchHistoryProps> = ({ onEdit }) => {
  const { matches, players, setMatchToEdit } = useApp();
  const [expandedMatchId, setExpandedMatchId] = useState<string | null>(null);

  const toggleExpand = (id: string) => {
    setExpandedMatchId(expandedMatchId === id ? null : id);
  };

  const handleEditClick = (e: React.MouseEvent, match: Match) => {
    e.stopPropagation();
    setMatchToEdit(match);
    if (onEdit) onEdit();
  };

  const formatDate = (isoString: string) => {
    return new Date(isoString).toLocaleDateString(undefined, {
      weekday: 'short',
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (matches.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-96 text-gray-400 animate-fade-in">
        <div className="bg-gray-100 dark:bg-gray-800 p-6 rounded-full mb-4">
          <Calendar size={48} />
        </div>
        <h3 className="text-xl font-bold dark:text-white">No Matches Recorded</h3>
        <p className="mt-2 text-center max-w-sm">Go to the "New Match" tab to track your first game!</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
        <Trophy className="text-pitch-600" /> Match History
      </h2>

      <div className="space-y-4">
        {matches.map((match) => {
          const isExpanded = expandedMatchId === match.id;
          const winner = match.scoreA > match.scoreB ? 'A' : match.scoreB > match.scoreA ? 'B' : 'Draw';

          return (
            <div key={match.id} className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden transition-all duration-300">
              {/* Match Header Summary */}
              <div 
                onClick={() => toggleExpand(match.id)}
                className="p-6 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
              >
                <div className="flex flex-col md:flex-row justify-between items-center gap-4">

                  {/* Date & Info */}
                  <div className="flex-1 text-center md:text-left">
                    <div className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-1">
                      {formatDate(match.date)}
                    </div>
                    <div className="flex items-center justify-center md:justify-start gap-2 text-sm text-gray-600 dark:text-gray-300">
                      <span className="bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded text-xs font-bold">
                        {match.type === MatchType.INTERNAL_FRIENDLY ? 'Friendly' : 'Challenger'}
                      </span>
                      <span className="flex items-center gap-1">
                         <MapPin size={12} /> {match.stadiumName || match.stadium}
                      </span>
                      {match.youtubeLink && (
                        <span className="text-red-500 flex items-center gap-0.5" title="Video Available">
                            <Youtube size={12} />
                        </span>
                      )}
                    </div>
                  </div>

                  {/* Scoreboard */}
                  <div className="flex items-center gap-6">
                    <div className={`text-right ${winner === 'A' ? 'font-bold text-gray-900 dark:text-white' : 'text-gray-500'}`}>
                      <div className="text-lg md:text-xl">{match.teamAName}</div>
                    </div>
                    <div className="flex items-center bg-gray-100 dark:bg-gray-900 rounded-lg px-4 py-2 gap-3">
                      <span className={`text-2xl md:text-3xl font-bold ${match.scoreA > match.scoreB ? 'text-pitch-600' : 'text-gray-700 dark:text-gray-300'}`}>
                        {match.scoreA}
                      </span>
                      <span className="text-gray-400">-</span>
                      <span className={`text-2xl md:text-3xl font-bold ${match.scoreB > match.scoreA ? 'text-pitch-600' : 'text-gray-700 dark:text-gray-300'}`}>
                        {match.scoreB}
                      </span>
                    </div>
                    <div className={`text-left ${winner === 'B' ? 'font-bold text-gray-900 dark:text-white' : 'text-gray-500'}`}>
                      <div className="text-lg md:text-xl">{match.teamBName}</div>
                    </div>
                  </div>

                  {/* Expand Icon */}
                  <div className="hidden md:flex items-center gap-4 text-gray-400">
                    <button 
                        onClick={(e) => handleEditClick(e, match)}
                        className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
                        title="Edit Match Details"
                    >
                        <Edit2 size={18} />
                    </button>
                    {isExpanded ? <ChevronUp size={24} /> : <ChevronDown size={24} />}
                  </div>
                </div>
              </div>

              {/* Expanded Details */}
              {isExpanded && (
                <div className="border-t border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-900/30 p-6 animate-slide-down">
                  {/* Action Bar inside expanded view for mobile visibility */}
                  <div className="md:hidden flex justify-end gap-2 mb-4">
                     <button 
                        onClick={(e) => handleEditClick(e, match)}
                        className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-gray-800 border dark:border-gray-700 rounded-lg text-sm font-medium"
                    >
                        <Edit2 size={14} /> Edit Match
                    </button>
                  </div>

                  {match.youtubeLink && (
                      <div className="mb-6">
                          <a 
                             href={match.youtubeLink} 
                             target="_blank" 
                             rel="noopener noreferrer"
                             className="inline-flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition-colors font-bold text-sm"
                          >
                             <Youtube size={18} /> Watch Highlights
                          </a>
                      </div>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    {/* Team A Stats */}
                    <div>
                      <h4 className="font-bold text-gray-500 dark:text-gray-400 mb-3 uppercase text-sm border-b dark:border-gray-700 pb-2 flex justify-between">
                         <span>{match.teamAName} Squad</span>
                         {winner === 'A' && <Trophy size={16} className="text-yellow-500" />}
                      </h4>
                      <div className="space-y-2">
                        {match.players.filter(p => p.team === 'A').map(mp => {
                          const player = players.find(p => p.id === mp.playerId);
                          return (
                            <div key={mp.playerId} className="flex items-center justify-between p-2 rounded bg-white dark:bg-gray-800 shadow-sm">
                               <div className="flex items-center gap-2">
                                  {player?.avatarUrl ? (
                                     <img src={player.avatarUrl} className="w-8 h-8 rounded-full" />
                                  ) : <User className="w-8 h-8 p-1 bg-gray-100 rounded-full" />}
                                  <div>
                                    <div className="text-sm font-bold dark:text-gray-200">{player?.name || 'Unknown'}</div>
                                    <div className="text-xs text-gray-400">{mp.isGK ? 'GK' : player?.position}</div>
                                  </div>
                               </div>
                               <div className="flex gap-2 text-xs">
                                  {mp.goals > 0 && (
                                    <span className="bg-green-100 text-green-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.goals} G
                                    </span>
                                  )}
                                  {mp.assists > 0 && (
                                    <span className="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.assists} A
                                    </span>
                                  )}
                                  {mp.ownGoals > 0 && (
                                    <span className="bg-red-100 text-red-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.ownGoals} OG
                                    </span>
                                  )}
                                  {mp.cleanSheet && (
                                    <span className="bg-yellow-100 text-yellow-700 px-1.5 py-0.5 rounded font-bold">
                                      CS
                                    </span>
                                  )}
                               </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>

                    {/* Team B Stats */}
                    <div>
                      <h4 className="font-bold text-gray-500 dark:text-gray-400 mb-3 uppercase text-sm border-b dark:border-gray-700 pb-2 flex justify-between">
                         <span>{match.teamBName} Squad</span>
                         {winner === 'B' && <Trophy size={16} className="text-yellow-500" />}
                      </h4>
                      <div className="space-y-2">
                        {match.players.filter(p => p.team === 'B').map(mp => {
                          const player = players.find(p => p.id === mp.playerId);
                          return (
                            <div key={mp.playerId} className="flex items-center justify-between p-2 rounded bg-white dark:bg-gray-800 shadow-sm">
                               <div className="flex items-center gap-2">
                                  {player?.avatarUrl ? (
                                     <img src={player.avatarUrl} className="w-8 h-8 rounded-full" />
                                  ) : <User className="w-8 h-8 p-1 bg-gray-100 rounded-full" />}
                                  <div>
                                    <div className="text-sm font-bold dark:text-gray-200">{player?.name || 'Unknown'}</div>
                                    <div className="text-xs text-gray-400">{mp.isGK ? 'GK' : player?.position}</div>
                                  </div>
                               </div>
                               <div className="flex gap-2 text-xs">
                                  {mp.goals > 0 && (
                                    <span className="bg-green-100 text-green-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.goals} G
                                    </span>
                                  )}
                                  {mp.assists > 0 && (
                                    <span className="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.assists} A
                                    </span>
                                  )}
                                  {mp.ownGoals > 0 && (
                                    <span className="bg-red-100 text-red-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.ownGoals} OG
                                    </span>
                                  )}
                                  {mp.cleanSheet && (
                                    <span className="bg-yellow-100 text-yellow-700 px-1.5 py-0.5 rounded font-bold">
                                      CS
                                    </span>
                                  )}
                               </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default MatchHistory;

