export default App;

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { Match, MatchType, StadiumSize, MatchPlayerStats, Position } from '../types';
import { Save, Search, Calendar, Clock, LayoutGrid, List, PlusCircle, MinusCircle, HelpCircle, Youtube, Edit2, Users, ArrowLeft } from 'lucide-react';
import { useToast } from '../context/ToastContext';

interface MatchManagerProps {
    onCancel?: () => void;
}

const MatchManager: React.FC<MatchManagerProps> = ({ onCancel }) => {
  const { players, addMatch, updateMatch, stadiums, matchToEdit, setMatchToEdit } = useApp();
  const { showToast } = useToast();

  const [step, setStep] = useState<1 | 2>(1); // 1: Setup, 2: Stats

  // Date & Time
  const [matchDate, setMatchDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [matchTime, setMatchTime] = useState(() => new Date().toTimeString().split(' ')[0].slice(0, 5));

  // Setup State
  const [matchType, setMatchType] = useState<MatchType>(MatchType.INTERNAL_FRIENDLY);
  const [youtubeLink, setYoutubeLink] = useState('');

  // Venue State
  const [selectedStadiumId, setSelectedStadiumId] = useState<string>('custom');
  const [customStadiumName, setCustomStadiumName] = useState('');
  const [stadiumSize, setStadiumSize] = useState<StadiumSize>(StadiumSize.MEDIUM);

  const [teamAName, setTeamAName] = useState('Team A');
  const [teamBName, setTeamBName] = useState('Team B');
  const [selectedPlayers, setSelectedPlayers] = useState<{ id: string, team: 'A' | 'B' }[]>([]);

  // Search State for Squad Selection
  const [squadSearch, setSquadSearch] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // Stats State
  // otherGoals stores goals that are NOT attributed to specific players (e.g. ringers, or generic own goals not attributed to an opponent player)
  const [otherGoalsA, setOtherGoalsA] = useState(0);
  const [otherGoalsB, setOtherGoalsB] = useState(0);
  const [playerPerformances, setPlayerPerformances] = useState<Record<string, { goals: number, assists: number, ownGoals: number, isGK: boolean, cleanSheet: boolean }>>({});

  // Effect to load match data if we are in Edit Mode
  useEffect(() => {
    if (matchToEdit) {
      // 1. Parse Date/Time
      const dateObj = new Date(matchToEdit.date);
      setMatchDate(dateObj.toISOString().split('T')[0]);
      setMatchTime(dateObj.toTimeString().split(' ')[0].slice(0, 5));

      // 2. Setup Logistics
      setMatchType(matchToEdit.type);
      setYoutubeLink(matchToEdit.youtubeLink || '');
      setTeamAName(matchToEdit.teamAName);
      setTeamBName(matchToEdit.teamBName);

      // 3. Stadium Logic
      const existingStadium = stadiums.find(s => s.name === matchToEdit.stadiumName && s.size === matchToEdit.stadium);
      if (existingStadium) {
        setSelectedStadiumId(existingStadium.id);
        setStadiumSize(existingStadium.size);
      } else {
        setSelectedStadiumId('custom');
        setCustomStadiumName(matchToEdit.stadiumName || '');
        setStadiumSize(matchToEdit.stadium);
      }

      // 4. Players & Performances
      const selection: { id: string, team: 'A' | 'B' }[] = [];
      const perfs: typeof playerPerformances = {};

      let calculatedScoreA = 0;
      let calculatedScoreB = 0;

      matchToEdit.players.forEach(mp => {
        selection.push({ id: mp.playerId, team: mp.team });
        perfs[mp.playerId] = {
          goals: mp.goals,
          assists: mp.assists,
          ownGoals: mp.ownGoals || 0,
          isGK: mp.isGK,
          cleanSheet: mp.cleanSheet
        };

        if (mp.team === 'A') {
            calculatedScoreA += mp.goals;
            calculatedScoreB += (mp.ownGoals || 0); // Own goals count for opponent
        } else {
            calculatedScoreB += mp.goals;
            calculatedScoreA += (mp.ownGoals || 0);
        }
      });

      setSelectedPlayers(selection);
      setPlayerPerformances(perfs);

      // 5. Calculate "Other Goals" by subtracting player contributions from total score
      setOtherGoalsA(Math.max(0, matchToEdit.scoreA - calculatedScoreA));
      setOtherGoalsB(Math.max(0, matchToEdit.scoreB - calculatedScoreB));

    } else {
      // Reset logic is handled by clearForm, but helpful to ensure defaults on mount if needed
    }
  }, [matchToEdit, stadiums]);

  const clearForm = () => {
    setMatchToEdit(null);
    setStep(1);
    setMatchDate(new Date().toISOString().split('T')[0]);
    setMatchTime(new Date().toTimeString().split(' ')[0].slice(0, 5));
    setMatchType(MatchType.INTERNAL_FRIENDLY);
    setYoutubeLink('');
    setSelectedStadiumId('custom');
    setCustomStadiumName('');
    setStadiumSize(StadiumSize.MEDIUM);
    setTeamAName('Team A');
    setTeamBName('Team B');
    setSelectedPlayers([]);
    setOtherGoalsA(0);
    setOtherGoalsB(0);
    setPlayerPerformances({});
  };

  const handleCancel = () => {
    if (matchToEdit) {
        setMatchToEdit(null);
        if (onCancel) {
            onCancel();
        } else {
            clearForm();
        }
    } else if (step === 2) {
        setStep(1);
    } else {
        clearForm();
    }
  };

  const teamAPlayers = selectedPlayers.filter(p => p.team === 'A');
  const teamBPlayers = selectedPlayers.filter(p => p.team === 'B');

  // Computed Scores
  const teamAGoalsFromPlayers = teamAPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.goals || 0), 0);
  const teamBOwnGoals = teamBPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.ownGoals || 0), 0);

  const teamBGoalsFromPlayers = teamBPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.goals || 0), 0);
  const teamAOwnGoals = teamAPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.ownGoals || 0), 0);

  const totalScoreA = teamAGoalsFromPlayers + teamBOwnGoals + otherGoalsA;
  const totalScoreB = teamBGoalsFromPlayers + teamAOwnGoals + otherGoalsB;

  const handleVenueChange = (val: string) => {
    setSelectedStadiumId(val);
    if (val !== 'custom') {
      const stadium = stadiums.find(s => s.id === val);
      if (stadium) {
        setStadiumSize(stadium.size);
      }
    } else {
        setCustomStadiumName('');
    }
  };

  const getEffectiveStadiumName = () => {
     if (selectedStadiumId === 'custom') return customStadiumName || 'Unknown Venue';
     const stadium = stadiums.find(s => s.id === selectedStadiumId);
     return stadium ? stadium.name : 'Unknown Venue';
  };

  const togglePlayerSelection = (playerId: string, team: 'A' | 'B') => {
    setSelectedPlayers(prev => {
      const exists = prev.find(p => p.id === playerId);
      if (exists) {
        if (exists.team === team) {
          // Deselect
          return prev.filter(p => p.id !== playerId);
        } else {
          // Switch team
          return prev.map(p => p.id === playerId ? { ...p, team } : p);
        }
      } else {
        // Add
        return [...prev, { id: playerId, team }];
      }
    });
  };

  const initializePerformance = () => {
    // If not editing, or if new players were added, ensure they have performance objects
    const perfs: typeof playerPerformances = { ...playerPerformances };
    selectedPlayers.forEach(p => {
      if (!perfs[p.id]) {
          perfs[p.id] = { goals: 0, assists: 0, ownGoals: 0, isGK: false, cleanSheet: false };
      }
    });
    setPlayerPerformances(perfs);
    setStep(2);
  };

  const updateStat = (playerId: string, field: keyof typeof playerPerformances[string], value: any) => {
    setPlayerPerformances(prev => ({
      ...prev,
      [playerId]: { ...prev[playerId], [field]: value }
    }));
  };

  const handleFinishMatch = () => {
    const combinedDate = new Date(`${matchDate}T${matchTime}`);

    const matchPlayers: MatchPlayerStats[] = selectedPlayers.map(sp => ({
      playerId: sp.id,
      team: sp.team,
      ...playerPerformances[sp.id]
    }));

    const matchData: Match = {
      id: matchToEdit ? matchToEdit.id : Date.now().toString(),
      date: combinedDate.toISOString(),
      type: matchType,
      stadium: stadiumSize,
      stadiumName: getEffectiveStadiumName(),
      youtubeLink: youtubeLink.trim() || undefined,
      teamAName,
      teamBName,
      scoreA: totalScoreA,
      scoreB: totalScoreB,
      players: matchPlayers
    };

    if (matchToEdit) {
        updateMatch(matchData);
        showToast("Match updated successfully!", "success");
        if (onCancel) onCancel(); // Return to history after edit
    } else {
        addMatch(matchData);
        showToast("Match saved successfully!", "success");
        clearForm(); // Reset form for next new match
    }
  };

  const filteredSquadList = players.filter(p => p.name.toLowerCase().includes(squadSearch.toLowerCase()));

  const positionColor = (pos: Position) => {
    switch (pos) {
        case Position.GK: return 'bg-yellow-100 text-yellow-800 border-yellow-200';
        case Position.DF: return 'bg-blue-100 text-blue-800 border-blue-200';
        case Position.MF: return 'bg-emerald-100 text-emerald-800 border-emerald-200';
        case Position.FW: return 'bg-red-100 text-red-800 border-red-200';
        default: return 'bg-gray-100';
    }
  };

  if (step === 1) {
    return (
      <div className="space-y-6 animate-fade-in pb-12">
        {matchToEdit && (
            <div className="bg-amber-50 dark:bg-amber-900/20 border-l-4 border-amber-500 p-4 rounded-r-lg flex items-start gap-3 shadow-sm">
                <Edit2 className="text-amber-600 dark:text-amber-400 mt-1" size={20} />
                <div>
                    <h3 className="font-bold text-amber-800 dark:text-amber-300">Editing Match Record</h3>
                    <p className="text-sm text-amber-700 dark:text-amber-400/80">
                        You are modifying a past match. Changes here will update your history and player stats.
                    </p>
                </div>
            </div>
        )}

        <div className="flex justify-between items-center">
            <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
                {matchToEdit ? 'Update Match Logistics' : 'New Match Setup'}
            </h2>
            {matchToEdit && (
                <button onClick={handleCancel} className="flex items-center gap-1 text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200 text-sm font-medium transition-colors">
                    <ArrowLeft size={16}/> Cancel Edit
                </button>
            )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
            <h3 className="font-bold mb-4 dark:text-gray-200 flex items-center gap-2">Match Logistics</h3>
            <div className="space-y-4">

              {/* Date and Time */}
              <div className="flex gap-4">
                 <div className="flex-1">
                    <label className="block text-sm text-gray-500 mb-1 flex items-center gap-1">
                        <Calendar size={14} /> Date
                    </label>
                    <input 
                       type="date"
                       className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                       value={matchDate}
                       onChange={(e) => setMatchDate(e.target.value)}
                    />
                 </div>
                 <div className="w-1/3">
                    <label className="block text-sm text-gray-500 mb-1 flex items-center gap-1">
                        <Clock size={14} /> Time
                    </label>
                    <input 
                       type="time"
                       className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                       value={matchTime}
                       onChange={(e) => setMatchTime(e.target.value)}
                    />
                 </div>
              </div>

              <div>
                <label className="block text-sm text-gray-500 mb-1">Type</label>
                <select 
                  className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                  value={matchType} onChange={(e) => setMatchType(e.target.value as MatchType)}>
                  {Object.values(MatchType).map(t => <option key={t} value={t}>{t.replace('_', ' ')}</option>)}
                </select>
              </div>

              {/* Stadium Selection */}
              <div>
                <label className="block text-sm text-gray-500 mb-1">Stadium</label>
                <select 
                  className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white mb-2"
                  value={selectedStadiumId} onChange={(e) => handleVenueChange(e.target.value)}>
                   {stadiums.map(s => <option key={s.id} value={s.id}>{s.name} ({s.size})</option>)}
                   <option value="custom">-- Custom Venue --</option>
                </select>

                {selectedStadiumId === 'custom' ? (
                   <div className="flex gap-2 animate-fade-in">
                      <input 
                        type="text" 
                        placeholder="Venue Name"
                        className="flex-1 p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                        value={customStadiumName}
                        onChange={(e) => setCustomStadiumName(e.target.value)}
                      />
                      <select 
                        className="w-32 p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                        value={stadiumSize} onChange={(e) => setStadiumSize(e.target.value as StadiumSize)}>
                        {Object.values(StadiumSize).map(t => <option key={t} value={t}>{t}</option>)}
                      </select>
                   </div>
                ) : (
                    <div className="text-sm text-gray-400 pl-1">
                        Applied Size: <span className="font-semibold text-pitch-600 dark:text-pitch-400">{stadiumSize}</span>
                    </div>
                )}
              </div>

              {/* YouTube Link */}
              <div>
                 <label className="block text-sm text-gray-500 mb-1 flex items-center gap-1">
                    <Youtube size={14} /> YouTube Link (Optional)
                 </label>
                 <input 
                    type="url" 
                    placeholder="https://youtu.be/..."
                    className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white"
                    value={youtubeLink}
                    onChange={(e) => setYoutubeLink(e.target.value)}
                 />
              </div>

              <div className="flex gap-4">
                <div className="flex-1">
                   <label className="block text-sm text-gray-500 mb-1">Team A Name</label>
                   <input className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white" value={teamAName} onChange={e => setTeamAName(e.target.value)} />
                </div>
                <div className="flex-1">
                   <label className="block text-sm text-gray-500 mb-1">Team B Name</label>
                   <input className="w-full p-2 rounded bg-gray-50 dark:bg-gray-900 border dark:border-gray-700 dark:text-white" value={teamBName} onChange={e => setTeamBName(e.target.value)} />
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col justify-between">
             <div>
                <h3 className="font-bold mb-4 dark:text-gray-200">Squad Allocation</h3>

                {/* Improved Summary UI - List Style instead of Scoreboard */}
                <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-xl mb-4 border border-gray-100 dark:border-gray-700">
                    <div className="flex justify-between items-center mb-2 pb-2 border-b border-gray-200 dark:border-gray-700">
                        <span className="font-bold text-gray-700 dark:text-gray-300 truncate max-w-[120px]">{teamAName}</span>
                        <div className="flex items-center gap-2" title="Assigned Players">
                            <Users size={14} className="text-gray-400"/>
                            <span className="font-mono font-bold text-pitch-600 text-sm">{teamAPlayers.length} Players</span>
                        </div>
                    </div>
                    <div className="flex justify-between items-center">
                        <span className="font-bold text-gray-700 dark:text-gray-300 truncate max-w-[120px]">{teamBName}</span>
                        <div className="flex items-center gap-2" title="Assigned Players">
                            <Users size={14} className="text-gray-400"/>
                            <span className="font-mono font-bold text-pitch-600 text-sm">{teamBPlayers.length} Players</span>
                        </div>
                    </div>
                </div>

                <div className="space-y-2 text-sm text-gray-600 dark:text-gray-400">
                    <div className="flex justify-between border-b dark:border-gray-700 pb-1">
                        <span>Date:</span>
                        <span className="font-medium dark:text-white">{matchDate} {matchTime}</span>
                    </div>
                    <div className="flex justify-between border-b dark:border-gray-700 pb-1">
                        <span>Venue:</span>
                        <span className="font-medium dark:text-white">{getEffectiveStadiumName()}</span>
                    </div>
                    <div className="flex justify-between">
                        <span>Type:</span>
                        <span className="font-medium dark:text-white">{matchType.replace('_', ' ')}</span>
                    </div>
                </div>
             </div>

             <button 
                disabled={selectedPlayers.length === 0}
                onClick={initializePerformance}
                className={`w-full mt-6 py-3 text-white rounded-xl font-bold transition-colors shadow-lg disabled:shadow-none flex items-center justify-center gap-2 ${matchToEdit ? 'bg-amber-600 hover:bg-amber-500' : 'bg-pitch-600 hover:bg-pitch-500 disabled:bg-gray-400'}`}
             >
                {matchToEdit ? <Edit2 size={18} /> : <Save size={18} />}
                {matchToEdit ? 'Continue to Edit Stats' : 'Start Match Tracking'}
             </button>
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
           <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
               <h3 className="font-bold dark:text-gray-200">Assign Players to Squads</h3>

               <div className="flex gap-2 w-full sm:w-auto">
                   <div className="relative flex-1 sm:w-64">
                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Search players..." 
                            value={squadSearch}
                            onChange={(e) => setSquadSearch(e.target.value)}
                            className="w-full pl-9 pr-4 py-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-sm focus:ring-1 focus:ring-pitch-500 outline-none dark:text-white"
                        />
                   </div>
                   <div className="flex bg-gray-50 dark:bg-gray-900 rounded-lg border border-gray-200 dark:border-gray-700 p-1">
                     <button 
                        onClick={() => setViewMode('grid')}
                        className={`p-1.5 rounded ${viewMode === 'grid' ? 'bg-white dark:bg-gray-700 text-pitch-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                     >
                        <LayoutGrid size={18} />
                     </button>
                     <button 
                        onClick={() => setViewMode('list')}
                        className={`p-1.5 rounded ${viewMode === 'list' ? 'bg-white dark:bg-gray-700 text-pitch-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                     >
                        <List size={18} />
                     </button>
                  </div>
               </div>
           </div>

           <div className="max-h-96 overflow-y-auto pr-2">
              {/* GRID VIEW */}
              {viewMode === 'grid' && (
                  <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                    {filteredSquadList.map(p => {
                        const selection = selectedPlayers.find(sp => sp.id === p.id);
                        return (
                        <div key={p.id} className={`p-3 rounded-lg border flex flex-col items-center gap-2 transition-all ${selection ? 'border-pitch-500 bg-pitch-50 dark:bg-pitch-900/20' : 'border-gray-200 dark:border-gray-700'}`}>
                            <div className="relative">
                                <img src={p.avatarUrl} className="w-12 h-12 rounded-full object-cover" alt={p.name} />
                                <span className={`absolute -bottom-1 -right-1 text-[10px] px-1.5 py-0.5 rounded font-bold uppercase ${positionColor(p.position)}`}>{p.position}</span>
                            </div>
                            <span className="font-medium text-sm dark:text-white truncate w-full text-center">{p.name}</span>
                            <div className="flex gap-2 w-full mt-1">
                                <button 
                                    onClick={() => togglePlayerSelection(p.id, 'A')}
                                    className={`flex-1 text-xs py-1.5 font-medium rounded transition-colors ${selection?.team === 'A' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                                    Team A
                                </button>
                                <button 
                                    onClick={() => togglePlayerSelection(p.id, 'B')}
                                    className={`flex-1 text-xs py-1.5 font-medium rounded transition-colors ${selection?.team === 'B' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                                    Team B
                                </button>
                            </div>
                        </div>
                        )
                    })}
                  </div>
              )}

              {/* LIST VIEW */}
              {viewMode === 'list' && (
                  <div className="space-y-2">
                      {filteredSquadList.map(p => {
                        const selection = selectedPlayers.find(sp => sp.id === p.id);
                        return (
                            <div key={p.id} className={`flex items-center justify-between p-3 rounded-lg border transition-all hover:bg-gray-50 dark:hover:bg-gray-800/50 ${selection ? 'border-pitch-500 bg-pitch-50 dark:bg-pitch-900/20' : 'border-gray-200 dark:border-gray-700'}`}>
                                <div className="flex items-center gap-4">
                                    <img src={p.avatarUrl} className="w-10 h-10 rounded-full object-cover" alt={p.name} />
                                    <div>
                                        <div className="font-bold dark:text-white text-sm">{p.name}</div>
                                        <div className={`text-[10px] inline-block px-1.5 rounded uppercase font-bold mt-0.5 ${positionColor(p.position)}`}>{p.position}</div>
                                    </div>
                                </div>
                                <div className="flex gap-2">
                                     <button 
                                        onClick={() => togglePlayerSelection(p.id, 'A')}
                                        className={`w-20 text-xs py-2 font-medium rounded transition-colors ${selection?.team === 'A' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                                        Team A
                                    </button>
                                    <button 
                                        onClick={() => togglePlayerSelection(p.id, 'B')}
                                        className={`w-20 text-xs py-2 font-medium rounded transition-colors ${selection?.team === 'B' ? 'bg-pitch-600 text-white shadow-md' : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300 hover:bg-gray-200'}`}>
                                        Team B
                                    </button>
                                </div>
                            </div>
                        )
                      })}
                  </div>
              )}
           </div>

           {filteredSquadList.length === 0 && (
               <div className="text-center py-8 text-gray-400">No players found matching "{squadSearch}"</div>
           )}
        </div>
      </div>
    );
  }

  // Step 2: Stats Input
  return (
    <div className="space-y-6 animate-fade-in pb-12">
        {matchToEdit && (
            <div className="bg-amber-50 dark:bg-amber-900/20 border-l-4 border-amber-500 p-4 rounded-r-lg flex items-start gap-3 shadow-sm mb-6">
                <Edit2 className="text-amber-600 dark:text-amber-400 mt-1" size={20} />
                <div>
                    <h3 className="font-bold text-amber-800 dark:text-amber-300">Editing Match Results</h3>
                    <p className="text-sm text-amber-700 dark:text-amber-400/80">
                        Updating goals and stats will modify the historical record for this match.
                    </p>
                </div>
            </div>
        )}

       <div className="flex justify-between items-center">
         <h2 className="text-3xl font-bold dark:text-white">{matchToEdit ? 'Update Results' : 'Match Result'}</h2>
         <button onClick={handleCancel} className="text-gray-500 hover:text-gray-700 dark:hover:text-gray-300">
            {matchToEdit ? 'Cancel Edit' : 'Go Back'}
         </button>
       </div>

       {/* Scoreboard Input */}
       <div className={`p-6 sm:p-8 rounded-2xl text-white shadow-lg relative overflow-hidden ${matchToEdit ? 'bg-amber-900' : 'bg-jersey-dark'}`}>
          <div className={`absolute top-0 left-0 w-full h-1 bg-gradient-to-r ${matchToEdit ? 'from-amber-500 to-orange-500' : 'from-pitch-500 to-blue-500'}`}></div>

          <div className="flex justify-center items-center gap-4 sm:gap-12 relative z-10">
            {/* Team A Score */}
            <div className="text-center flex-1">
                <h3 className={`text-lg sm:text-xl mb-2 font-bold truncate ${matchToEdit ? 'text-amber-400' : 'text-pitch-400'}`}>{teamAName}</h3>
                <div className="text-5xl sm:text-7xl font-bold tracking-tight">{totalScoreA}</div>
                <div className="flex items-center justify-center gap-2 mt-2">
                    <span className="text-xs text-gray-400">Other:</span>
                    <div className="flex items-center gap-1 bg-white/10 rounded-lg px-2 py-1">
                        <button onClick={() => setOtherGoalsA(Math.max(0, otherGoalsA - 1))} className={`hover:text-white ${matchToEdit ? 'text-amber-300' : 'text-pitch-400'}`}><MinusCircle size={14}/></button>
                        <span className="text-sm font-mono w-4 text-center">{otherGoalsA}</span>
                        <button onClick={() => setOtherGoalsA(otherGoalsA + 1)} className={`hover:text-white ${matchToEdit ? 'text-amber-300' : 'text-pitch-400'}`}><PlusCircle size={14}/></button>
                    </div>
                </div>
            </div>

            <div className="text-3xl sm:text-5xl font-thin text-gray-600">-</div>

            {/* Team B Score */}
            <div className="text-center flex-1">
                <h3 className={`text-lg sm:text-xl mb-2 font-bold truncate ${matchToEdit ? 'text-amber-400' : 'text-blue-400'}`}>{teamBName}</h3>
                <div className="text-5xl sm:text-7xl font-bold tracking-tight">{totalScoreB}</div>
                <div className="flex items-center justify-center gap-2 mt-2">
                    <span className="text-xs text-gray-400">Other:</span>
                    <div className="flex items-center gap-1 bg-white/10 rounded-lg px-2 py-1">
                        <button onClick={() => setOtherGoalsB(Math.max(0, otherGoalsB - 1))} className={`hover:text-white ${matchToEdit ? 'text-amber-300' : 'text-pitch-400'}`}><MinusCircle size={14}/></button>
                        <span className="text-sm font-mono w-4 text-center">{otherGoalsB}</span>
                        <button onClick={() => setOtherGoalsB(otherGoalsB + 1)} className={`hover:text-white ${matchToEdit ? 'text-amber-300' : 'text-pitch-400'}`}><PlusCircle size={14}/></button>
                    </div>
                </div>
            </div>
          </div>

          <div className="text-center mt-6 text-xs text-gray-500 flex justify-center gap-4">
               <span>Date: {matchDate} {matchTime}</span>
               <span>•</span>
               <span>Venue: {getEffectiveStadiumName()}</span>
          </div>
       </div>

       <div className="flex items-center gap-2 text-sm text-gray-500 bg-blue-50 dark:bg-blue-900/20 p-3 rounded-lg border border-blue-100 dark:border-blue-900/30">
          <HelpCircle size={16} className="text-blue-500" />
          <span>Score updates automatically. "Other" tracks goals not attributed to listed players. <strong className="text-pitch-600 dark:text-pitch-400">Own Goals (OG)</strong> count toward the opponent.</span>
       </div>

       {/* Player Stats Input */}
       <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {[
              { team: 'A', name: teamAName, players: teamAPlayers, otherGoals: otherGoalsA, total: totalScoreA }, 
              { team: 'B', name: teamBName, players: teamBPlayers, otherGoals: otherGoalsB, total: totalScoreB }
            ].map((group) => (
            <div key={group.team} className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
               <div className="flex justify-between items-center mb-4 border-b border-gray-100 dark:border-gray-700 pb-2">
                   <h3 className={`font-bold text-xl ${matchToEdit ? 'text-amber-600' : 'text-pitch-600'}`}>{group.name} Stats</h3>
                   <div className="text-sm text-gray-400">Total: <span className="text-gray-900 dark:text-white font-bold">{group.total}</span></div>
               </div>

               <div className="space-y-4">
                  {group.players.map(sp => {
                     const p = players.find(x => x.id === sp.id)!;
                     const stats = playerPerformances[p.id];
                     return (
                        <div key={p.id} className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-900 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors">
                           <img src={p.avatarUrl} className="w-10 h-10 rounded-full bg-white" alt={p.name} />
                           <div className="flex-1 min-w-0">
                             <div className="font-bold truncate dark:text-white text-sm">{p.name}</div>
                             <div className="text-xs text-gray-500">{p.position}</div>
                           </div>

                           {/* Goal Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">Goals</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border rounded dark:bg-gray-800 dark:border-gray-600 dark:text-white focus:border-pitch-500 outline-none"
                                value={stats.goals}
                                onChange={e => updateStat(p.id, 'goals', parseInt(e.target.value))}
                              />
                           </div>

                           {/* Assist Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">Asst</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border rounded dark:bg-gray-800 dark:border-gray-600 dark:text-white focus:border-pitch-500 outline-none"
                                value={stats.assists}
                                onChange={e => updateStat(p.id, 'assists', parseInt(e.target.value))}
                              />
                           </div>

                           {/* Own Goal Input */}
                           <div className="flex flex-col items-center">
                              <span className="text-[10px] text-red-400 mb-0.5 uppercase font-bold" title="Own Goal">OG</span>
                              <input 
                                type="number" min="0" className="w-10 p-1 text-center text-sm border border-red-200 dark:border-red-900 rounded dark:bg-gray-800 dark:text-white focus:border-red-500 outline-none"
                                value={stats.ownGoals}
                                onChange={e => updateStat(p.id, 'ownGoals', parseInt(e.target.value))}
                              />
                           </div>

                           {/* GK Toggle */}
                           <div className="flex flex-col items-center px-1">
                              <span className="text-[10px] text-gray-400 mb-0.5 uppercase">GK</span>
                              <input 
                                type="checkbox" className={`w-5 h-5 rounded cursor-pointer ${matchToEdit ? 'accent-amber-600' : 'accent-pitch-600'}`}
                                checked={stats.isGK}
                                onChange={e => updateStat(p.id, 'isGK', e.target.checked)}
                              />
                           </div>

                           {/* Clean Sheet (Only if GK) */}
                           {stats.isGK && (
                             <div className="flex flex-col items-center animate-fade-in px-1">
                                <span className="text-[10px] text-gray-400 mb-0.5 uppercase">CS</span>
                                <input 
                                  type="checkbox" className={`w-5 h-5 rounded cursor-pointer ${matchToEdit ? 'accent-amber-600' : 'accent-pitch-600'}`}
                                  checked={stats.cleanSheet}
                                  onChange={e => updateStat(p.id, 'cleanSheet', e.target.checked)}
                                />
                             </div>
                           )}
                        </div>
                     )
                  })}
               </div>
            </div>
          ))}
       </div>

       <div className="flex justify-end pt-6">
          <button 
            onClick={handleFinishMatch}
            className={`text-white px-8 py-4 rounded-xl font-bold text-lg shadow-xl flex items-center gap-3 transition-transform hover:scale-105 ${matchToEdit ? 'bg-amber-600 hover:bg-amber-500' : 'bg-pitch-600 hover:bg-pitch-500'}`}
          >
            <Save size={24} />
            {matchToEdit ? 'Update Match Results' : 'Save Match Results'}
          </button>
       </div>
    </div>
  );
};

export default MatchManager;

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { Match, MatchType, StadiumSize, MatchPlayerStats, Position } from '../types';
import { Save, Search, Calendar, Clock, LayoutGrid, List, PlusCircle, MinusCircle, HelpCircle, Youtube, Edit2, Users, ArrowLeft } from 'lucide-react';
import { useToast } from '../context/ToastContext';

interface MatchManagerProps {
    onCancel?: () => void;
}

const MatchManager: React.FC<MatchManagerProps> = ({ onCancel }) => {
  const { players, addMatch, updateMatch, stadiums, matchToEdit, setMatchToEdit } = useApp();
  const { showToast } = useToast();

  const [step, setStep] = useState<1 | 2>(1); // 1: Setup, 2: Stats

  // Date & Time
  const [matchDate, setMatchDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [matchTime, setMatchTime] = useState(() => new Date().toTimeString().split(' ')[0].slice(0, 5));

  // Setup State
  const [matchType, setMatchType] = useState<MatchType>(MatchType.INTERNAL_FRIENDLY);
  const [youtubeLink, setYoutubeLink] = useState('');

  // Venue State
  const [selectedStadiumId, setSelectedStadiumId] = useState<string>('custom');
  const [customStadiumName, setCustomStadiumName] = useState('');
  const [stadiumSize, setStadiumSize] = useState<StadiumSize>(StadiumSize.MEDIUM);

  const [teamAName, setTeamAName] = useState('Team A');
  const [teamBName, setTeamBName] = useState('Team B');
  const [selectedPlayers, setSelectedPlayers] = useState<{ id: string, team: 'A' | 'B' }[]>([]);

  // Search State for Squad Selection
  const [squadSearch, setSquadSearch] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // Stats State
  // otherGoals stores goals that are NOT attributed to specific players (e.g. ringers, or generic own goals not attributed to an opponent player)
  const [otherGoalsA, setOtherGoalsA] = useState(0);
  const [otherGoalsB, setOtherGoalsB] = useState(0);
  const [playerPerformances, setPlayerPerformances] = useState<Record<string, { goals: number, assists: number, ownGoals: number, isGK: boolean, cleanSheet: boolean }>>({});

  // Effect to load match data if we are in Edit Mode
  useEffect(() => {
    if (matchToEdit) {
      // 1. Parse Date/Time
      const dateObj = new Date(matchToEdit.date);
      setMatchDate(dateObj.toISOString().split('T')[0]);
      setMatchTime(dateObj.toTimeString().split(' ')[0].slice(0, 5));

      // 2. Setup Logistics
      setMatchType(matchToEdit.type);
      setYoutubeLink(matchToEdit.youtubeLink || '');
      setTeamAName(matchToEdit.teamAName);
      setTeamBName(matchToEdit.teamBName);

      // 3. Stadium Logic
      const existingStadium = stadiums.find(s => s.name === matchToEdit.stadiumName && s.size === matchToEdit.stadium);
      if (existingStadium) {
        setSelectedStadiumId(existingStadium.id);
        setStadiumSize(existingStadium.size);
      } else {
        setSelectedStadiumId('custom');
        setCustomStadiumName(matchToEdit.stadiumName || '');
        setStadiumSize(matchToEdit.stadium);
      }

      // 4. Players & Performances
      const selection: { id: string, team: 'A' | 'B' }[] = [];
      const perfs: typeof playerPerformances = {};

      let calculatedScoreA = 0;
      let calculatedScoreB = 0;

      matchToEdit.players.forEach(mp => {
        selection.push({ id: mp.playerId, team: mp.team });
        perfs[mp.playerId] = {
          goals: mp.goals,
          assists: mp.assists,
          ownGoals: mp.ownGoals || 0,
          isGK: mp.isGK,
          cleanSheet: mp.cleanSheet
        };

        if (mp.team === 'A') {
            calculatedScoreA += mp.goals;
            calculatedScoreB += (mp.ownGoals || 0); // Own goals count for opponent
        } else {
            calculatedScoreB += mp.goals;
            calculatedScoreA += (mp.ownGoals || 0);
        }
      });

      setSelectedPlayers(selection);
      setPlayerPerformances(perfs);

      // 5. Calculate "Other Goals" by subtracting player contributions from total score
      setOtherGoalsA(Math.max(0, matchToEdit.scoreA - calculatedScoreA));
      setOtherGoalsB(Math.max(0, matchToEdit.scoreB - calculatedScoreB));

    } else {
      // Reset logic is handled by clearForm, but helpful to ensure defaults on mount if needed
    }
  }, [matchToEdit, stadiums]);

  const clearForm = () => {
    setMatchToEdit(null);
    setStep(1);
    setMatchDate(new Date().toISOString().split('T')[0]);
    setMatchTime(new Date().toTimeString().split(' ')[0].slice(0, 5));
    setMatchType(MatchType.INTERNAL_FRIENDLY);
    setYoutubeLink('');
    setSelectedStadiumId('custom');
    setCustomStadiumName('');
    setStadiumSize(StadiumSize.MEDIUM);
    setTeamAName('Team A');
    setTeamBName('Team B');
    setSelectedPlayers([]);
    setOtherGoalsA(0);
    setOtherGoalsB(0);
    setPlayerPerformances({});
  };

  const handleCancel = () => {
    if (matchToEdit) {
        // Confirm before discarding changes in Edit Mode
        if (window.confirm("Are you sure you want to stop editing?\n\nAny unsaved changes to this match record will be lost.")) {
            setMatchToEdit(null);
            if (onCancel) {
                onCancel();
            } else {
                clearForm();
            }
        }
    } else if (step === 2) {
        // Go back to Step 1 (Preserves state, no warning needed)
        setStep(1);
    } else {
        clearForm();
    }
  };

  const teamAPlayers = selectedPlayers.filter(p => p.team === 'A');
  const teamBPlayers = selectedPlayers.filter(p => p.team === 'B');

  // Computed Scores
  const teamAGoalsFromPlayers = teamAPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.goals || 0), 0);
  const teamBOwnGoals = teamBPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.ownGoals || 0), 0);

  const teamBGoalsFromPlayers = teamBPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.goals || 0), 0);
  const teamAOwnGoals = teamAPlayers.reduce((sum, p) => sum + (playerPerformances[p.id]?.ownGoals || 0), 0);

  const totalScoreA = teamAGoalsFromPlayers + teamBOwnGoals + otherGoalsA;
  const totalScoreB = teamBGoalsFromPlayers + teamAOwnGoals + otherGoalsB;

  const handleVenueChange = (val: string) => {
    setSelectedStadiumId(val);
    if (val !== 'custom') {
      const stadium = stadiums.find(s => s.id === val);
      if (stadium) {
        setStadiumSize(stadium.size);
      }
    } else {
        setCustomStadiumName('');
    }
  };

  const getEffectiveStadiumName = () => {
     if (selectedStadiumId === 'custom') return customStadiumName || 'Unknown Venue';
     const stadium = stadiums.find(s => s.id === selectedStadiumId);
     return stadium ? stadium.name : 'Unknown Venue';
  };

  const togglePlayerSelection = (playerId: string, team: 'A' | 'B') => {
    setSelectedPlayers(prev => {
      const exists = prev.find(p => p.id === playerId);
      if (exists) {
        if (exists.team === team) {
          // Deselect
          return prev.filter(p => p.id !== playerId);
        } else {
          // Switch team
          return prev.map(p => p.id === playerId ? { ...p, team } : p);
        }
      } else {
        // Add
        return [...prev, { id: playerId, team }];
      }
    });
  };

  const initializePerformance = () => {
    // If not editing, or if new players were added, ensure they have performance objects
    const perfs: typeof playerPerformances = { ...playerPerformances };
    selectedPlayers.forEach(p => {
      if (!perfs[p.id]) {
          perfs[p.id] = { goals: 0, assists: 0, ownGoals: 0, isGK: false, cleanSheet: false };
      }
    });
    setPlayerPerformances(perfs);
    setStep(2);
  };

  const updateStat = (playerId: string, field: keyof typeof playerPerformances[string], value: any) => {
    setPlayerPerformances(prev => ({
      ...prev,
      [playerId]: { ...prev[playerId], [field]: value }
    }));
  };

  const handleFinishMatch = () => {
    const combinedDate = new Date(`${matchDate}T${matchTime}`);

    const matchPlayers: MatchPlayerStats[] = selectedPlayers.map(sp => ({
      playerId: sp.id,
      team: sp.team,
      ...playerPerformances[sp.id]
    }));

    const matchData: Match = {
      id: matchToEdit ? matchToEdit.id : Date.now().toString(),
      date: combinedDate.toISOString(),
      type: matchType,
      stadium: stadiumSize,
      stadiumName: getEffectiveStadiumName(),
      youtubeLink: youtubeLink.trim() || undefined,
      teamAName,
      teamBName,
      scoreA: totalScoreA,
      scoreB: totalScoreB,
      players: matchPlayers
    };

    if (matchToEdit) {
        updateMatch(matchData);
        showToast("Match updated successfully!", "success");
        if (onCancel) onCancel(); // Return to history after edit
    } else {
        addMatch(matchData);
        showToast("Match saved successfully!", "success");
        clearForm(); // Reset form for next new match
    }
  };

  const filteredSquadList = players.filter(p => p.name.toLowerCase().includes(squadSearch.toLowerCase()));

  const positionColor = (pos: Position) => {
    switch (pos) {
        case Position.GK: return 'bg-yellow-100 text-yellow-800 border-yellow-200';
        case Position.DF: return 'bg-blue-100 text-blue-800 border-blue-200';
        case Position.MF: return 'bg-emerald-100 text-emerald-800 border-emerald-200';
        case Position.FW: return 'bg-red-100 text-red-800 border-red-200';
        default: return 'bg-gray-100';
    }
  };

  if (step === 1) {
    return (
      <div className="space-y-6 animate-fade-in pb-12">
        {matchToEdit && (
            <div className="bg-amber-50 dark:bg-amber-900/20 border-l-4 border-amber-500 p-4 rounded-r-lg flex items-start gap-3 shadow-sm">
                <Edit2 className="text-amber-600 dark:text-amber-400 mt-1" size={20} />
                <div>
                    <h3 className="font-bold text-amber-800 dark:text-amber-300">Editing Match Record</h3>
                    <p className="text-sm text-amber-700 dark:text-amber-400/80">
                        You are modifying a past match. Changes here will update your history and player stats.
