  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [searchQuery, setSearchQuery] = useState('');

  const filteredPlayers = players.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleOpenAdd = () => {
      setModalMode('add');
      setFormName('');
      setFormPosition(Position.MF);
      setEditingId(null);
      setIsModalOpen(true);
  };

  const handleOpenEdit = (player: Player) => {
      setModalMode('edit');
      setFormName(player.name);
      setFormPosition(player.position);
      setEditingId(player.id);
      setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formName.trim()) return;

    if (modalMode === 'add') {
        const newPlayer: Player = {
            id: Date.now().toString(),
            name: formName,
            position: formPosition,
            avatarUrl: `https://ui-avatars.com/api/?name=${formName}&background=random`
        };
        addPlayer(newPlayer);
        showToast('Player recruited successfully!', 'success');
    } else {
        if (editingId) {
            const existing = players.find(p => p.id === editingId);
            if (existing) {
                updatePlayer({
                    ...existing,
                    name: formName,
                    position: formPosition
                });
                showToast('Player details updated.', 'success');
            }
        }
    }
    setIsModalOpen(false);
  };

  const handleDeleteClick = (player: Player) => {
      setPlayerToDelete(player);
  };

  const confirmDelete = () => {
    if (playerToDelete) {
      deletePlayer(playerToDelete.id);
      showToast(`${playerToDelete.name} has been released.`, 'info');
      setPlayerToDelete(null);
    }
  };

  const handleGenerateAvatar = async (player: Player) => {
    if (generatingId) return; 
    setGeneratingId(player.id);

    try {
        let desc = "";
        if (player.position === Position.GK) desc = "wearing goalkeeper gloves, focused, defending goal";
        else if (player.position === Position.FW) desc = "striking a ball, aggressive striker pose";
        else desc = "dribbling a football, dynamic midfield action";

        const imageUrl = await generatePlayerAvatar(player.name, desc);
        updatePlayerAvatar(player.id, imageUrl);
        showToast('New avatar generated!', 'success');
    } catch (err) {
        showToast("Failed to generate avatar. Check API Key.", 'error');
    } finally {
        setGeneratingId(null);
    }
  };

  const handleViewStats = (player: Player) => {
      setViewingPlayer(player);
  };

  const positionColor = (pos: Position) => {
    switch (pos) {
        case Position.GK: return 'bg-yellow-500 text-yellow-50 border-yellow-200';
        case Position.DF: return 'bg-blue-500 text-blue-50 border-blue-200';
        case Position.MF: return 'bg-emerald-500 text-emerald-50 border-emerald-200';
        case Position.FW: return 'bg-red-500 text-red-50 border-red-200';
        default: return 'bg-gray-500';
    }
  };

  return (
    <div className="space-y-6 animate-fade-in relative">

      {/* Profile Modal */}
      {viewingPlayer && (
          <PlayerProfile player={viewingPlayer} onClose={() => setViewingPlayer(null)} />
      )}

      {/* Delete Confirmation Modal */}
      {playerToDelete && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
          <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 max-w-sm w-full shadow-2xl border dark:border-gray-700 animate-slide-up">
            <div className="flex items-center gap-3 text-red-600 mb-4">
               <div className="p-2 bg-red-100 dark:bg-red-900/30 rounded-full">
                 <AlertTriangle size={24} />
               </div>
               <h3 className="text-xl font-bold text-gray-900 dark:text-white">Release Player?</h3>
            </div>
            <p className="text-gray-600 dark:text-gray-300 mb-2">
               Are you sure you want to remove <strong>{playerToDelete.name}</strong> from the squad?
            </p>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-6 bg-gray-50 dark:bg-gray-700/50 p-3 rounded-lg border border-gray-100 dark:border-gray-600">
               ⚠️ Matches played by this player will remain in history, but they will be marked as 'Unknown' if edited in the future.
            </p>
            <div className="flex gap-3">
              <button 
                onClick={() => setPlayerToDelete(null)}
                className="flex-1 py-2.5 px-4 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-xl font-medium hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
              >
                Cancel
              </button>
              <button 
                onClick={confirmDelete}
                className="flex-1 py-2.5 px-4 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold transition-colors shadow-lg"
              >
                Yes, Release
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Header Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-3xl font-bold dark:text-white">Squad</h2>

        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
          {/* Search */}
          <div className="relative flex-1 sm:w-64">
             <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
             <input 
                type="text" 
                placeholder="Find player..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white"
             />
          </div>

          {/* View Toggle */}
          <div className="flex bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-1">
             <button 
                onClick={() => setViewMode('grid')}
                className={`p-2 rounded ${viewMode === 'grid' ? 'bg-pitch-100 text-pitch-600 dark:bg-pitch-900/30 dark:text-pitch-400' : 'text-gray-400 hover:text-gray-600'}`}
             >
                <LayoutGrid size={20} />
             </button>
             <button 
                onClick={() => setViewMode('list')}
                className={`p-2 rounded ${viewMode === 'list' ? 'bg-pitch-100 text-pitch-600 dark:bg-pitch-900/30 dark:text-pitch-400' : 'text-gray-400 hover:text-gray-600'}`}
             >
                <List size={20} />
             </button>
          </div>

          <button
            onClick={handleOpenAdd}
            className="bg-pitch-600 hover:bg-pitch-500 text-white px-4 py-2 rounded-lg flex items-center justify-center gap-2 shadow-lg transition-all"
          >
            <UserPlus size={20} />
            Add Player
          </button>
        </div>
      </div>

      {filteredPlayers.length === 0 && (
         <div className="text-center py-12 text-gray-500 dark:text-gray-400 bg-white dark:bg-gray-800 rounded-2xl border border-dashed border-gray-300 dark:border-gray-700">
             <p>No players found.</p>
         </div>
      )}

      {/* Grid View */}
      {viewMode === 'grid' && (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {filteredPlayers.map((player) => (
            <div key={player.id} className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm hover:shadow-xl transition-all duration-300 overflow-hidden border border-gray-100 dark:border-gray-700 group">
              <div 
                  className="relative h-48 bg-gray-100 dark:bg-gray-900 overflow-hidden cursor-pointer"
                  onClick={() => handleViewStats(player)}
              >
                  <img 
                      src={player.avatarUrl} 
                      alt={player.name} 
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                  />
                  <div className="absolute top-2 right-2">
                      <span className={`${positionColor(player.position)} border px-2 py-1 rounded-full text-xs font-bold uppercase tracking-wider shadow-sm`}>
                          {player.position}
                      </span>
                  </div>
                  {/* Hover Overlay Actions */}
                  <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-3">

                      <button 
                          onClick={(e) => { e.stopPropagation(); handleViewStats(player); }}
                          className="bg-white text-pitch-600 px-4 py-2 rounded-full font-bold flex items-center justify-center gap-2 hover:bg-gray-100 transform hover:scale-105 transition-all shadow-lg"
                      >
                          <Activity size={18} />
                          View Stats
                      </button>

                      <div className="flex gap-2">
                           <button 
                            onClick={(e) => { e.stopPropagation(); handleGenerateAvatar(player); }}
                            disabled={generatingId === player.id}
                            className="bg-gray-800/80 text-white p-2 rounded-full font-bold hover:bg-gray-700 transform hover:scale-110 transition-all shadow-md backdrop-blur-sm"
                            title="Generate Avatar"
                          >
                             {generatingId === player.id ? <span className="animate-spin text-xs">⌛</span> : <Sparkles size={16} />}
                          </button>
                          <button 
                            onClick={(e) => { e.stopPropagation(); handleOpenEdit(player); }}
                            className="bg-amber-500 text-white p-2 rounded-full font-bold hover:bg-amber-600 transform hover:scale-110 transition-all shadow-md"
                            title="Edit"
                          >
                             <Edit2 size={16} />
                          </button>
                          <button 
                            onClick={(e) => { e.stopPropagation(); handleDeleteClick(player); }}
                            className="bg-red-500 text-white p-2 rounded-full font-bold hover:bg-red-600 transform hover:scale-110 transition-all shadow-md"
                            title="Delete"
                          >
                             <Trash2 size={16} />
                          </button>
                      </div>
                  </div>
              </div>
              <div className="p-4" onClick={() => handleViewStats(player)}>
                <div className="flex justify-between items-start cursor-pointer">
                    <div>
                        <h3 className="text-xl font-bold dark:text-white truncate max-w-[150px] group-hover:text-pitch-600 transition-colors">{player.name}</h3>
                        <p className="text-sm text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-1">
                            <Shirt size={14} /> #{player.id.slice(-3)}
                        </p>
                    </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* List View */}
      {viewMode === 'list' && (
         <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden">
            <div className="overflow-x-auto">
               <table className="w-full text-left">
                  <thead className="bg-gray-50 dark:bg-gray-900/50 text-gray-500 dark:text-gray-400 uppercase text-xs">
                     <tr>
                        <th className="p-4 font-medium">Player</th>
                        <th className="p-4 font-medium">Position</th>
                        <th className="p-4 font-medium">ID</th>
                        <th className="p-4 font-medium text-right">Actions</th>
                     </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                     {filteredPlayers.map(player => (
                        <tr key={player.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/30 transition-colors group cursor-pointer" onClick={() => handleViewStats(player)}>
                           <td className="p-4">
                              <div className="flex items-center gap-3">
                                 <img src={player.avatarUrl} className="w-10 h-10 rounded-full object-cover bg-gray-100" alt={player.name} />
                                 <span className="font-bold dark:text-white group-hover:text-pitch-600 transition-colors">{player.name}</span>
                              </div>
                           </td>
                           <td className="p-4">
                              <span className={`${positionColor(player.position)} px-2 py-1 rounded-full text-xs font-bold uppercase`}>
                                 {player.position}
                              </span>
                           </td>
                           <td className="p-4 text-gray-500 dark:text-gray-400 font-mono text-sm">
                              #{player.id.slice(-4)}
                           </td>
                           <td className="p-4 text-right">
                              <div className="flex items-center justify-end gap-2" onClick={(e) => e.stopPropagation()}>
                                 <button 
                                    onClick={() => handleViewStats(player)}
                                    title="View Stats"
                                    className="p-2 text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded-lg transition-colors"
                                 >
                                    <Activity size={18} />
                                 </button>
                                 <button 
                                    onClick={() => handleGenerateAvatar(player)}
                                    disabled={generatingId === player.id}
                                    title="Generate Avatar"
                                    className="p-2 text-pitch-600 hover:bg-pitch-50 dark:hover:bg-pitch-900/30 rounded-lg transition-colors"
                                 >
                                    {generatingId === player.id ? <span className="animate-spin text-xs">⌛</span> : <Sparkles size={18} />}
                                 </button>
                                 <button 
                                    onClick={() => handleOpenEdit(player)}
                                    title="Edit Details"
                                    className="p-2 text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/30 rounded-lg transition-colors"
                                 >
                                    <Edit2 size={18} />
                                 </button>
                                 <button 
                                    onClick={() => handleDeleteClick(player)}
                                    title="Remove Player"
                                    className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-lg transition-colors"
                                 >
                                    <Trash2 size={18} />
                                 </button>
                              </div>
                           </td>
                        </tr>
                     ))}
                  </tbody>
               </table>
            </div>
         </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-fade-in">
          <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl w-full max-w-md shadow-2xl border dark:border-gray-700 animate-slide-up relative">
            <button 
                onClick={() => setIsModalOpen(false)}
                className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"
            >
                <X size={20} />
            </button>
            <h3 className="text-2xl font-bold mb-6 dark:text-white flex items-center gap-2">
                {modalMode === 'add' ? <UserPlus className="text-pitch-600"/> : <Edit2 className="text-amber-500"/>}
                {modalMode === 'add' ? 'Recruit New Player' : 'Update Player Details'}
            </h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Name</label>
                <input
                  type="text"
                  required
                  autoFocus
                  className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white transition-all"
                  value={formName}
                  onChange={(e) => setFormName(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Position</label>
                <select
                  className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white transition-all"
                  value={formPosition}
                  onChange={(e) => setFormPosition(e.target.value as Position)}
                >
                  {Object.values(Position).map((pos) => (
                    <option key={pos} value={pos}>{pos}</option>
                  ))}
                </select>
              </div>
              <div className="flex gap-3 mt-6">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className={`flex-1 px-4 py-2 text-white rounded-lg font-medium shadow-md transition-colors ${modalMode === 'add' ? 'bg-pitch-600 hover:bg-pitch-500' : 'bg-amber-600 hover:bg-amber-500'}`}
                >
                  {modalMode === 'add' ? 'Add to Squad' : 'Save Changes'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default PlayerList;

import React from 'react';
import { Player, Position } from '../types';
import { useApp } from '../context/AppContext';
import { X, Trophy, Target, Footprints, Shield, TrendingUp, Percent, Hash, Activity } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip, Legend } from 'recharts';

interface PlayerProfileProps {
    player: Player;
    onClose: () => void;
}

const PlayerProfile: React.FC<PlayerProfileProps> = ({ player, onClose }) => {
    const { getPlayerStats } = useApp();
    const stats = getPlayerStats(player.id);

    const winRate = stats.matchesPlayed > 0 ? ((stats.wins / stats.matchesPlayed) * 100).toFixed(1) : '0';
    const contributionPerMatch = stats.matchesPlayed > 0 ? ((stats.goals + stats.assists) / stats.matchesPlayed).toFixed(2) : '0';

    const pieData = [
        { name: 'Wins', value: stats.wins, color: '#10b981' }, // pitch-500
        { name: 'Draws', value: stats.draws, color: '#9ca3af' }, // gray-400
        { name: 'Losses', value: stats.losses, color: '#ef4444' }, // red-500
    ].filter(d => d.value > 0);

    const positionColor = (pos: Position) => {
        switch (pos) {
            case Position.GK: return 'bg-yellow-100 text-yellow-800 border-yellow-200 dark:bg-yellow-900/30 dark:text-yellow-300 dark:border-yellow-700';
            case Position.DF: return 'bg-blue-100 text-blue-800 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-700';
            case Position.MF: return 'bg-emerald-100 text-emerald-800 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-700';
            case Position.FW: return 'bg-red-100 text-red-800 border-red-200 dark:bg-red-900/30 dark:text-red-300 dark:border-red-700';
            default: return 'bg-gray-100';
        }
    };

    const handleBackdropClick = (e: React.MouseEvent<HTMLDivElement>) => {
        if (e.target === e.currentTarget) {
            onClose();
        }
    };

    return (
        <div 
            onClick={handleBackdropClick}
            className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md animate-fade-in overflow-y-auto"
        >
            <div className="bg-white dark:bg-gray-800 w-full max-w-4xl rounded-3xl shadow-2xl border dark:border-gray-700 overflow-hidden flex flex-col max-h-[90vh] animate-slide-up relative">

                {/* Close Button - Increased Z-index and contrast */}
                <button 
                    onClick={onClose}
                    className="absolute top-4 right-4 z-50 p-2 bg-black/20 hover:bg-black/40 text-white rounded-full transition-colors backdrop-blur-sm"
                    aria-label="Close Profile"
                >
                    <X size={24} />
                </button>

                {/* Header Section */}
                <div className="bg-jersey-dark relative overflow-hidden shrink-0">
                    <div className="absolute inset-0 bg-gradient-to-br from-pitch-900/50 to-blue-900/50"></div>
                    <div className="relative p-8 flex flex-col sm:flex-row items-center sm:items-end gap-6">
                         <div className="relative">
                            <div className="w-32 h-32 rounded-full border-4 border-white dark:border-gray-700 shadow-xl overflow-hidden bg-white">
                                <img src={player.avatarUrl} alt={player.name} className="w-full h-full object-cover" />
                            </div>
                            <span className={`absolute bottom-0 right-0 px-3 py-1 rounded-full text-xs font-bold uppercase border-2 border-white dark:border-gray-800 shadow-md ${positionColor(player.position)}`}>
                                {player.position}
                            </span>
                         </div>
                         <div className="text-center sm:text-left text-white mb-2">
                            <h2 className="text-4xl font-bold tracking-tight">{player.name}</h2>
                            <div className="flex items-center justify-center sm:justify-start gap-4 mt-2 text-gray-300 text-sm">
                                <span className="flex items-center gap-1"><Hash size={14}/> ID: {player.id.slice(-4)}</span>
                                <span className="flex items-center gap-1 bg-white/10 px-2 py-0.5 rounded"><Trophy size={14} className="text-yellow-400"/> Rating: {stats.weightedRating.toFixed(1)}</span>
                            </div>
                         </div>
                    </div>
                </div>

                {/* Content Scroll Area */}
                <div className="overflow-y-auto p-6 sm:p-8 space-y-8 bg-gray-50 dark:bg-gray-900/50 flex-1">

                    {/* Key Stats Grid */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col items-center justify-center gap-1">
                            <span className="text-gray-400 text-xs font-bold uppercase tracking-wider">Matches</span>
                            <span className="text-3xl font-bold text-gray-900 dark:text-white">{stats.matchesPlayed}</span>
                            <Footprints size={16} className="text-pitch-500 mt-1" />
                        </div>
                        <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col items-center justify-center gap-1">
                            <span className="text-gray-400 text-xs font-bold uppercase tracking-wider">Goals</span>
                            <span className="text-3xl font-bold text-gray-900 dark:text-white">{stats.goals}</span>
                            <Target size={16} className="text-blue-500 mt-1" />
                        </div>
                        <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col items-center justify-center gap-1">
                            <span className="text-gray-400 text-xs font-bold uppercase tracking-wider">Assists</span>
                            <span className="text-3xl font-bold text-gray-900 dark:text-white">{stats.assists}</span>
                            <TrendingUp size={16} className="text-purple-500 mt-1" />
                        </div>
                        <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col items-center justify-center gap-1">
                            <span className="text-gray-400 text-xs font-bold uppercase tracking-wider">Win Rate</span>
                            <span className="text-3xl font-bold text-gray-900 dark:text-white">{winRate}%</span>
                            <Percent size={16} className="text-orange-500 mt-1" />
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        {/* Win/Loss Chart */}
                        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 md:col-span-1">
                            <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
                                <Activity size={20} className="text-pitch-600"/> Match Record
                            </h3>
                            <div className="h-48 w-full relative">
                                {stats.matchesPlayed > 0 ? (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <PieChart>
                                            <Pie
                                                data={pieData}
                                                cx="50%"
                                                cy="50%"
                                                innerRadius={40}
                                                outerRadius={70}
                                                paddingAngle={5}
                                                dataKey="value"
                                                stroke="none"
                                            >
                                                {pieData.map((entry, index) => (
                                                    <Cell key={`cell-${index}`} fill={entry.color} />
                                                ))}
                                            </Pie>
                                            <RechartsTooltip 
                                                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                                            />
                                            <Legend verticalAlign="bottom" height={36} iconType="circle"/>
                                        </PieChart>
                                    </ResponsiveContainer>
                                ) : (
                                    <div className="flex items-center justify-center h-full text-gray-400 text-sm italic">No matches played</div>
                                )}
                            </div>
                        </div>

                        {/* Detailed Stats List */}
                        <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 md:col-span-2">
                             <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
                                <Activity size={20} className="text-blue-500"/> Performance Metrics
                            </h3>
                            <div className="space-y-4">
                                <div className="flex justify-between items-center p-3 bg-gray-50 dark:bg-gray-900/50 rounded-lg">
