import { useToast } from '../context/ToastContext';

const Settings: React.FC = () => {
  const { settings, updateSettings, stadiums, addStadium, updateStadium, deleteStadium, resetData } = useApp();
  const { showToast } = useToast();

  // Local state for the form to avoid excessive context updates while typing
  const [localSettings, setLocalSettings] = useState(settings);

  // State for stadium form
  const [editingStadiumId, setEditingStadiumId] = useState<string | null>(null);
  const [formStadiumName, setFormStadiumName] = useState('');
  const [formStadiumSize, setFormStadiumSize] = useState<StadiumSize>(StadiumSize.MEDIUM);

  // Sync local state if context settings change (e.g. from a reset elsewhere)
  useEffect(() => {
    setLocalSettings(settings);
  }, [settings]);

  const handleSaveSettings = () => {
    updateSettings(localSettings);
    showToast('Configuration saved. Stats recalculated.', 'success');
  };

  const handleResetDefaults = () => {
    if (confirm('Reset scoring weights to defaults? Your player data will be safe.')) {
        const defaults = {
            matchTypeWeights: { ...MATCH_TYPE_WEIGHTS },
            stadiumSizeWeights: { ...STADIUM_SIZE_WEIGHTS },
            basePoints: { ...BASE_POINTS }
        };
        setLocalSettings(defaults);
        updateSettings(defaults);
        showToast('Weights reset to defaults.', 'info');
    }
  };

  const handleSubmitStadium = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formStadiumName.trim()) return;

    if (editingStadiumId) {
        // Update Mode
        const updated: Stadium = {
            id: editingStadiumId,
            name: formStadiumName,
            size: formStadiumSize
        };
        updateStadium(updated);
        showToast('Stadium updated successfully!', 'success');
        resetStadiumForm();
    } else {
        // Add Mode
        const newStadium: Stadium = {
            id: Date.now().toString(),
            name: formStadiumName,
            size: formStadiumSize
        };
        addStadium(newStadium);
        showToast('Stadium added successfully!', 'success');
        resetStadiumForm();
    }
  };

  const handleEditClick = (stadium: Stadium) => {
      setEditingStadiumId(stadium.id);
      setFormStadiumName(stadium.name);
      setFormStadiumSize(stadium.size);
  };

  const handleDeleteStadium = (id: string, name: string) => {
    if (confirm(`Are you sure you want to delete "${name}"?`)) {
      deleteStadium(id);
      showToast('Stadium removed.', 'info');
      if (editingStadiumId === id) {
          resetStadiumForm();
      }
    }
  };

  const resetStadiumForm = () => {
      setEditingStadiumId(null);
      setFormStadiumName('');
      setFormStadiumSize(StadiumSize.MEDIUM);
  };

  const updateMatchTypeWeight = (type: MatchType, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        matchTypeWeights: {
            ...prev.matchTypeWeights,
            [type]: parseFloat(val) || 0
        }
    }));
  };

  const updateStadiumWeight = (size: StadiumSize, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        stadiumSizeWeights: {
            ...prev.stadiumSizeWeights,
            [size]: parseFloat(val) || 0
        }
    }));
  };

  const updateBasePoint = (key: keyof typeof BASE_POINTS, val: string) => {
    setLocalSettings(prev => ({
        ...prev,
        basePoints: {
            ...prev.basePoints,
            [key]: parseFloat(val) || 0
        }
    }));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-12">
      <div className="flex items-center justify-between">
         <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
             <SettingsIcon className="text-pitch-600" size={32} />
             Settings
