         <button 
            onClick={resetData}
            type="button"
            className="flex items-center gap-2 px-4 py-2 text-white bg-red-600 hover:bg-red-700 rounded-lg transition-colors shadow-md"
         >
            <Database size={18} />
            Factory Reset App
         </button>
      </div>

      {/* Stadium Management Section */}
      <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
         <div className="flex items-center gap-2 mb-6 border-b dark:border-gray-700 pb-2">
            <MapPin className="text-pitch-600" size={24} />
            <h3 className="font-bold text-xl dark:text-white">Stadium Management</h3>
         </div>

         <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
               <div className="flex items-center justify-between mb-3">
                 <h4 className={`font-medium text-sm uppercase tracking-wider ${editingStadiumId ? 'text-amber-500' : 'text-gray-500 dark:text-gray-400'}`}>
                    {editingStadiumId ? 'Editing Venue' : 'Add New Venue'}
