import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Match, MatchType } from '../types';
import { Calendar, MapPin, Trophy, ChevronDown, ChevronUp, User, Youtube, Edit2, Trash2, AlertTriangle } from 'lucide-react';
import { useToast } from '../context/ToastContext';

interface MatchHistoryProps {
  onEdit?: () => void;
}

const MatchHistory: React.FC<MatchHistoryProps> = ({ onEdit }) => {
  const { matches, players, setMatchToEdit, deleteMatch } = useApp();
  const { showToast } = useToast();
  const [expandedMatchId, setExpandedMatchId] = useState<string | null>(null);
  const [matchToDelete, setMatchToDelete] = useState<Match | null>(null);

  const toggleExpand = (id: string) => {
    setExpandedMatchId(expandedMatchId === id ? null : id);
  };

  const handleEditClick = (e: React.MouseEvent, match: Match) => {
    e.stopPropagation();
    setMatchToEdit(match);
    if (onEdit) onEdit();
  };

  const handleDeleteClick = (e: React.MouseEvent, match: Match) => {
      e.stopPropagation();
      setMatchToDelete(match);
  };

  const confirmDelete = () => {
      if (matchToDelete) {
          deleteMatch(matchToDelete.id);
          showToast('Match deleted successfully.', 'info');
          setMatchToDelete(null);
      }
  };

  const formatDate = (isoString: string) => {
    return new Date(isoString).toLocaleDateString(undefined, {
      weekday: 'short',
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (matches.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-96 text-gray-400 animate-fade-in">
        <div className="bg-gray-100 dark:bg-gray-800 p-6 rounded-full mb-4">
          <Calendar size={48} />
        </div>
        <h3 className="text-xl font-bold dark:text-white">No Matches Recorded</h3>
        <p className="mt-2 text-center max-w-sm">Go to the "New Match" tab to track your first game!</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in relative">

      {/* Delete Confirmation Modal */}
      {matchToDelete && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
          <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 max-w-sm w-full shadow-2xl border dark:border-gray-700 animate-slide-up">
            <div className="flex items-center gap-3 text-red-600 mb-4">
               <div className="p-2 bg-red-100 dark:bg-red-900/30 rounded-full">
                 <AlertTriangle size={24} />
               </div>
               <h3 className="text-xl font-bold text-gray-900 dark:text-white">Delete Match?</h3>
            </div>
            <p className="text-gray-600 dark:text-gray-300 mb-2">
               Are you sure you want to delete the match between <strong>{matchToDelete.teamAName}</strong> and <strong>{matchToDelete.teamBName}</strong>?
            </p>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-6 bg-gray-50 dark:bg-gray-700/50 p-3 rounded-lg border border-gray-100 dark:border-gray-600">
               ⚠️ This action cannot be undone. Player stats from this match will be removed.
            </p>
            <div className="flex gap-3">
              <button 
                onClick={() => setMatchToDelete(null)}
                className="flex-1 py-2.5 px-4 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-xl font-medium hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
              >
                Cancel
              </button>
              <button 
                onClick={confirmDelete}
                className="flex-1 py-2.5 px-4 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold transition-colors shadow-lg"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}

      <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
        <Trophy className="text-pitch-600" /> Match History
      </h2>

      <div className="space-y-4">
        {matches.map((match) => {
          const isExpanded = expandedMatchId === match.id;
          const winner = match.scoreA > match.scoreB ? 'A' : match.scoreB > match.scoreA ? 'B' : 'Draw';

          return (
            <div key={match.id} className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden transition-all duration-300">
              {/* Match Header Summary */}
              <div 
                onClick={() => toggleExpand(match.id)}
                className="p-6 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
              >
                <div className="flex flex-col md:flex-row justify-between items-center gap-4">

                  {/* Date & Info */}
                  <div className="flex-1 text-center md:text-left">
                    <div className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-1">
                      {formatDate(match.date)}
                    </div>
                    <div className="flex items-center justify-center md:justify-start gap-2 text-sm text-gray-600 dark:text-gray-300">
                      <span className="bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded text-xs font-bold">
                        {match.type === MatchType.INTERNAL_FRIENDLY ? 'Friendly' : 'Challenger'}
                      </span>
                      <span className="flex items-center gap-1">
                         <MapPin size={12} /> {match.stadiumName || match.stadium}
                      </span>
                      {match.youtubeLink && (
                        <span className="text-red-500 flex items-center gap-0.5" title="Video Available">
                            <Youtube size={12} />
                        </span>
                      )}
                    </div>
                  </div>

                  {/* Scoreboard */}
                  <div className="flex items-center gap-6">
                    <div className={`text-right ${winner === 'A' ? 'font-bold text-gray-900 dark:text-white' : 'text-gray-500'}`}>
                      <div className="text-lg md:text-xl">{match.teamAName}</div>
                    </div>
                    <div className="flex items-center bg-gray-100 dark:bg-gray-900 rounded-lg px-4 py-2 gap-3">
                      <span className={`text-2xl md:text-3xl font-bold ${match.scoreA > match.scoreB ? 'text-pitch-600' : 'text-gray-700 dark:text-gray-300'}`}>
                        {match.scoreA}
                      </span>
                      <span className="text-gray-400">-</span>
                      <span className={`text-2xl md:text-3xl font-bold ${match.scoreB > match.scoreA ? 'text-pitch-600' : 'text-gray-700 dark:text-gray-300'}`}>
                        {match.scoreB}
                      </span>
                    </div>
                    <div className={`text-left ${winner === 'B' ? 'font-bold text-gray-900 dark:text-white' : 'text-gray-500'}`}>
                      <div className="text-lg md:text-xl">{match.teamBName}</div>
                    </div>
                  </div>

                  {/* Expand Icon */}
                  <div className="hidden md:flex items-center gap-2 text-gray-400">
                    <button 
                        onClick={(e) => handleEditClick(e, match)}
                        className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors hover:text-amber-500"
                        title="Edit Match Details"
                    >
                        <Edit2 size={18} />
                    </button>
                    <button 
                        onClick={(e) => handleDeleteClick(e, match)}
                        className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors hover:text-red-500"
                        title="Delete Match"
                    >
                        <Trash2 size={18} />
                    </button>
                    <div className="pl-2 border-l dark:border-gray-700">
                        {isExpanded ? <ChevronUp size={24} /> : <ChevronDown size={24} />}
                    </div>
                  </div>
                </div>
              </div>

              {/* Expanded Details */}
              {isExpanded && (
                <div className="border-t border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-900/30 p-6 animate-slide-down">
                  {/* Action Bar inside expanded view for mobile visibility */}
                  <div className="md:hidden flex justify-end gap-2 mb-4">
                     <button 
                        onClick={(e) => handleEditClick(e, match)}
                        className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-gray-800 border dark:border-gray-700 rounded-lg text-sm font-medium text-amber-600"
                    >
                        <Edit2 size={14} /> Edit
                    </button>
                    <button 
                        onClick={(e) => handleDeleteClick(e, match)}
                        className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-gray-800 border dark:border-gray-700 rounded-lg text-sm font-medium text-red-600"
                    >
                        <Trash2 size={14} /> Delete
                    </button>
                  </div>

                  {match.youtubeLink && (
                      <div className="mb-6">
                          <a 
                             href={match.youtubeLink} 
                             target="_blank" 
                             rel="noopener noreferrer"
                             className="inline-flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition-colors font-bold text-sm"
                          >
                             <Youtube size={18} /> Watch Highlights
                          </a>
                      </div>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    {/* Team A Stats */}
                    <div>
                      <h4 className="font-bold text-gray-500 dark:text-gray-400 mb-3 uppercase text-sm border-b dark:border-gray-700 pb-2 flex justify-between">
                         <span>{match.teamAName} Squad</span>
                         {winner === 'A' && <Trophy size={16} className="text-yellow-500" />}
                      </h4>
                      <div className="space-y-2">
                        {match.players.filter(p => p.team === 'A').map(mp => {
                          const player = players.find(p => p.id === mp.playerId);
                          return (
                            <div key={mp.playerId} className="flex items-center justify-between p-2 rounded bg-white dark:bg-gray-800 shadow-sm">
                               <div className="flex items-center gap-2">
                                  {player?.avatarUrl ? (
                                     <img src={player.avatarUrl} className="w-8 h-8 rounded-full" />
                                  ) : <User className="w-8 h-8 p-1 bg-gray-100 rounded-full" />}
                                  <div>
                                    <div className="text-sm font-bold dark:text-gray-200">{player?.name || 'Unknown'}</div>
                                    <div className="text-xs text-gray-400">{mp.isGK ? 'GK' : player?.position}</div>
                                  </div>
                               </div>
                               <div className="flex gap-2 text-xs">
                                  {mp.goals > 0 && (
                                    <span className="bg-green-100 text-green-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.goals} G
                                    </span>
                                  )}
                                  {mp.assists > 0 && (
                                    <span className="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.assists} A
                                    </span>
                                  )}
                                  {mp.ownGoals > 0 && (
                                    <span className="bg-red-100 text-red-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.ownGoals} OG
                                    </span>
                                  )}
                                  {mp.cleanSheet && (
                                    <span className="bg-yellow-100 text-yellow-700 px-1.5 py-0.5 rounded font-bold">
                                      CS
                                    </span>
                                  )}
                               </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>

                    {/* Team B Stats */}
                    <div>
                      <h4 className="font-bold text-gray-500 dark:text-gray-400 mb-3 uppercase text-sm border-b dark:border-gray-700 pb-2 flex justify-between">
                         <span>{match.teamBName} Squad</span>
                         {winner === 'B' && <Trophy size={16} className="text-yellow-500" />}
                      </h4>
                      <div className="space-y-2">
                        {match.players.filter(p => p.team === 'B').map(mp => {
                          const player = players.find(p => p.id === mp.playerId);
                          return (
                            <div key={mp.playerId} className="flex items-center justify-between p-2 rounded bg-white dark:bg-gray-800 shadow-sm">
                               <div className="flex items-center gap-2">
                                  {player?.avatarUrl ? (
                                     <img src={player.avatarUrl} className="w-8 h-8 rounded-full" />
                                  ) : <User className="w-8 h-8 p-1 bg-gray-100 rounded-full" />}
                                  <div>
                                    <div className="text-sm font-bold dark:text-gray-200">{player?.name || 'Unknown'}</div>
                                    <div className="text-xs text-gray-400">{mp.isGK ? 'GK' : player?.position}</div>
                                  </div>
                               </div>
                               <div className="flex gap-2 text-xs">
                                  {mp.goals > 0 && (
                                    <span className="bg-green-100 text-green-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.goals} G
                                    </span>
                                  )}
                                  {mp.assists > 0 && (
                                    <span className="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.assists} A
                                    </span>
                                  )}
                                  {mp.ownGoals > 0 && (
                                    <span className="bg-red-100 text-red-700 px-1.5 py-0.5 rounded font-bold">
                                      {mp.ownGoals} OG
                                    </span>
                                  )}
                                  {mp.cleanSheet && (
                                    <span className="bg-yellow-100 text-yellow-700 px-1.5 py-0.5 rounded font-bold">
                                      CS
                                    </span>
                                  )}
                               </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default MatchHistory;

import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { MatchType, StadiumSize, Stadium } from '../types';
import { Save, RotateCcw, Settings as SettingsIcon, MapPin, Plus, Trash2, Database, Edit2, X, Search, LayoutGrid, List, AlertTriangle, Ruler } from 'lucide-react';
import { MATCH_TYPE_WEIGHTS, STADIUM_SIZE_WEIGHTS, BASE_POINTS } from '../constants';
import { useToast } from '../context/ToastContext';

const Settings: React.FC = () => {
  const { settings, updateSettings, stadiums, addStadium, updateStadium, deleteStadium, resetData } = useApp();
  const { showToast } = useToast();

  // -- TABS STATE --
  const [activeTab, setActiveTab] = useState<'venues' | 'rules'>('venues');

  // -- RULES STATE --
  const [localSettings, setLocalSettings] = useState(settings);
  useEffect(() => { setLocalSettings(settings); }, [settings]);

  // -- VENUE MANAGEMENT STATE --
  const [searchQuery, setSearchQuery] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // Modals
  const [isStadiumModalOpen, setIsStadiumModalOpen] = useState(false);
  const [stadiumToDelete, setStadiumToDelete] = useState<Stadium | null>(null);

  // Form State
  const [editingStadiumId, setEditingStadiumId] = useState<string | null>(null);
  const [formStadiumName, setFormStadiumName] = useState('');
  const [formStadiumSize, setFormStadiumSize] = useState<StadiumSize>(StadiumSize.MEDIUM);

  // -- RULES HANDLERS --
  const handleSaveSettings = () => {
    updateSettings(localSettings);
    showToast('Configuration saved. Stats recalculated.', 'success');
  };

  const handleResetDefaults = () => {
    if (confirm('Reset scoring weights to defaults?')) {
        const defaults = {
            matchTypeWeights: { ...MATCH_TYPE_WEIGHTS },
            stadiumSizeWeights: { ...STADIUM_SIZE_WEIGHTS },
            basePoints: { ...BASE_POINTS }
        };
        setLocalSettings(defaults);
        updateSettings(defaults);
        showToast('Weights reset to defaults.', 'info');
    }
  };

  const updateMatchTypeWeight = (type: MatchType, val: string) => {
    setLocalSettings(prev => ({ ...prev, matchTypeWeights: { ...prev.matchTypeWeights, [type]: parseFloat(val) || 0 } }));
  };

  const updateStadiumWeight = (size: StadiumSize, val: string) => {
    setLocalSettings(prev => ({ ...prev, stadiumSizeWeights: { ...prev.stadiumSizeWeights, [size]: parseFloat(val) || 0 } }));
  };

  const updateBasePoint = (key: keyof typeof BASE_POINTS, val: string) => {
    setLocalSettings(prev => ({ ...prev, basePoints: { ...prev.basePoints, [key]: parseFloat(val) || 0 } }));
  };

  // -- VENUE HANDLERS --
  const filteredStadiums = stadiums.filter(s => s.name.toLowerCase().includes(searchQuery.toLowerCase()));

  const handleOpenAddStadium = () => {
      setEditingStadiumId(null);
      setFormStadiumName('');
      setFormStadiumSize(StadiumSize.MEDIUM);
      setIsStadiumModalOpen(true);
  };

  const handleOpenEditStadium = (s: Stadium) => {
      setEditingStadiumId(s.id);
      setFormStadiumName(s.name);
      setFormStadiumSize(s.size);
      setIsStadiumModalOpen(true);
  };

  const handleStadiumSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formStadiumName.trim()) return;

    if (editingStadiumId) {
        updateStadium({ id: editingStadiumId, name: formStadiumName, size: formStadiumSize });
        showToast('Stadium details updated.', 'success');
    } else {
        addStadium({ id: Date.now().toString(), name: formStadiumName, size: formStadiumSize });
        showToast('New venue added.', 'success');
    }
    setIsStadiumModalOpen(false);
  };

  const confirmDeleteStadium = () => {
      if (stadiumToDelete) {
          deleteStadium(stadiumToDelete.id);
          showToast('Venue removed.', 'info');
          setStadiumToDelete(null);
      }
  };

  const sizeColor = (size: StadiumSize) => {
      switch(size) {
          case StadiumSize.SMALL: return 'bg-emerald-100 text-emerald-800 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-700';
          case StadiumSize.MEDIUM: return 'bg-blue-100 text-blue-800 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-700';
          case StadiumSize.LARGE: return 'bg-purple-100 text-purple-800 border-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-700';
          default: return 'bg-gray-100';
      }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in pb-12 relative">

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
         <div>
            <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
                <SettingsIcon className="text-pitch-600" size={32} />
                Settings & Venues
            </h2>
            <p className="text-gray-500 dark:text-gray-400 mt-1">Manage playing venues and adjust scoring algorithms.</p>
         </div>
         <div className="flex bg-gray-200 dark:bg-gray-700 p-1 rounded-xl">
            <button 
                onClick={() => setActiveTab('venues')}
                className={`px-4 py-2 rounded-lg font-medium transition-all ${activeTab === 'venues' ? 'bg-white dark:bg-gray-600 text-pitch-600 dark:text-white shadow-sm' : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300'}`}
            >
                Venue Management
            </button>
            <button 
                onClick={() => setActiveTab('rules')}
                className={`px-4 py-2 rounded-lg font-medium transition-all ${activeTab === 'rules' ? 'bg-white dark:bg-gray-600 text-pitch-600 dark:text-white shadow-sm' : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300'}`}
            >
                Scoring Rules
            </button>
         </div>
      </div>

      {/* --- VENUE MANAGEMENT TAB --- */}
      {activeTab === 'venues' && (
        <div className="space-y-6 animate-slide-up">

            {/* Controls */}
            <div className="flex flex-col sm:flex-row justify-between items-center gap-4 bg-white dark:bg-gray-800 p-4 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm">
                <div className="relative flex-1 w-full">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                        type="text" 
                        placeholder="Search venues..." 
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white"
                    />
                </div>
                <div className="flex gap-2 w-full sm:w-auto">
                    <div className="flex bg-gray-50 dark:bg-gray-900 rounded-lg border border-gray-200 dark:border-gray-700 p-1">
                        <button onClick={() => setViewMode('grid')} className={`p-2 rounded ${viewMode === 'grid' ? 'bg-white dark:bg-gray-700 text-pitch-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}><LayoutGrid size={20} /></button>
                        <button onClick={() => setViewMode('list')} className={`p-2 rounded ${viewMode === 'list' ? 'bg-white dark:bg-gray-700 text-pitch-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}><List size={20} /></button>
                    </div>
                    <button 
                        onClick={handleOpenAddStadium}
                        className="bg-pitch-600 hover:bg-pitch-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 shadow-md transition-all flex-1 sm:flex-none justify-center"
                    >
                        <Plus size={20} /> Add Venue
                    </button>
                </div>
            </div>

            {/* Content */}
            {viewMode === 'grid' ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredStadiums.map(s => (
                        <div key={s.id} className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm hover:shadow-md transition-shadow border border-gray-100 dark:border-gray-700 overflow-hidden group relative">
                            <div className={`h-24 ${sizeColor(s.size).split(' ')[0]} bg-opacity-30 relative overflow-hidden`}>
                                 <MapPin className="absolute -bottom-4 -right-4 text-current opacity-10 w-32 h-32" />
                            </div>
                            <div className="p-5">
                                <div className="flex justify-between items-start mb-2">
                                    <h3 className="font-bold text-lg dark:text-white truncate">{s.name}</h3>
                                </div>
                                <div className="flex items-center gap-2 mb-4">
                                     <span className={`px-2 py-1 rounded text-xs font-bold uppercase border ${sizeColor(s.size)}`}>
                                        {s.size} Pitch
                                     </span>
                                </div>
                                <div className="flex gap-2 pt-2 border-t dark:border-gray-700">
                                    <button onClick={() => handleOpenEditStadium(s)} className="flex-1 py-2 rounded-lg text-sm font-medium bg-gray-50 dark:bg-gray-700/50 text-gray-600 dark:text-gray-300 hover:bg-amber-50 dark:hover:bg-amber-900/20 hover:text-amber-600 transition-colors flex items-center justify-center gap-2">
                                        <Edit2 size={16} /> Edit
                                    </button>
                                    <button onClick={() => setStadiumToDelete(s)} className="flex-1 py-2 rounded-lg text-sm font-medium bg-gray-50 dark:bg-gray-700/50 text-gray-600 dark:text-gray-300 hover:bg-red-50 dark:hover:bg-red-900/20 hover:text-red-600 transition-colors flex items-center justify-center gap-2">
                                        <Trash2 size={16} /> Delete
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                    {filteredStadiums.length === 0 && (
                        <div className="col-span-full text-center py-12 text-gray-400 bg-gray-50 dark:bg-gray-800/50 rounded-2xl border border-dashed border-gray-200 dark:border-gray-700">
                            <MapPin className="mx-auto mb-3 opacity-50" size={48} />
                            <p>No venues found. Add one to get started!</p>
                        </div>
                    )}
                </div>
            ) : (
                <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden">
                    {filteredStadiums.map(s => (
                         <div key={s.id} className="p-4 border-b border-gray-100 dark:border-gray-700 last:border-0 flex items-center justify-between hover:bg-gray-50 dark:hover:bg-gray-700/30 transition-colors">
                             <div className="flex items-center gap-4">
                                 <div className={`p-3 rounded-lg ${sizeColor(s.size)}`}>
                                     <MapPin size={20} />
                                 </div>
                                 <div>
                                     <div className="font-bold dark:text-white">{s.name}</div>
                                     <div className="text-xs text-gray-500">{s.size} Pitch</div>
                                 </div>
                             </div>
                             <div className="flex gap-2">
                                 <button onClick={() => handleOpenEditStadium(s)} className="p-2 text-gray-400 hover:text-amber-600 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-lg transition-colors">
                                     <Edit2 size={18} />
                                 </button>
                                 <button onClick={() => setStadiumToDelete(s)} className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors">
                                     <Trash2 size={18} />
                                 </button>
                             </div>
                         </div>
                    ))}
                    {filteredStadiums.length === 0 && (
                        <div className="p-8 text-center text-gray-400 italic">No venues found.</div>
                    )}
                </div>
            )}
        </div>
      )}

      {/* --- SCORING RULES TAB --- */}
      {activeTab === 'rules' && (
        <div className="space-y-6 animate-slide-up">
            <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 p-4 rounded-xl flex items-start gap-3">
                <Ruler className="text-blue-600 dark:text-blue-400 mt-1" size={20} />
                <div>
                    <h3 className="font-bold text-blue-800 dark:text-blue-300">Scoring Algorithm</h3>
                    <p className="text-sm text-blue-700 dark:text-blue-400/80 mt-1">
                        The app calculates a <strong>Weighted Rating</strong> for each player using the formula:
                        <br/>
                        <code className="bg-white/50 dark:bg-black/20 px-1 py-0.5 rounded mt-1 inline-block">Rating = (Base Points) × (Match Multiplier) × (Stadium Multiplier)</code>
                    </p>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Multipliers */}
                <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                    <h3 className="font-bold text-xl mb-6 dark:text-white border-b dark:border-gray-700 pb-2">Multipliers</h3>
                    <div className="space-y-6">
                        <div>
                            <h4 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-3">Match Difficulty</h4>
                            <div className="space-y-3">
                                {Object.values(MatchType).map((type) => (
                                    <div key={type} className="flex justify-between items-center">
                                        <label className="text-gray-700 dark:text-gray-300 font-medium">{type.replace('_', ' ')}</label>
                                        <input 
                                            type="number" step="0.1"
                                            value={localSettings.matchTypeWeights[type]}
                                            onChange={(e) => updateMatchTypeWeight(type, e.target.value)}
                                            className="w-20 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none"
                                        />
                                    </div>
                                ))}
                            </div>
                        </div>
                        <div>
                            <h4 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-3">Pitch Size</h4>
                            <div className="space-y-3">
                                {Object.values(StadiumSize).map((size) => (
                                    <div key={size} className="flex justify-between items-center">
                                        <label className="text-gray-700 dark:text-gray-300 font-medium">{size}</label>
                                        <input 
                                            type="number" step="0.1"
                                            value={localSettings.stadiumSizeWeights[size]}
                                            onChange={(e) => updateStadiumWeight(size, e.target.value)}
                                            className="w-20 p-2 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg text-right font-mono dark:text-white focus:ring-2 focus:ring-pitch-500 outline-none"
                                        />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Base Points */}
                <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700">
                    <div className="flex justify-between items-center border-b dark:border-gray-700 pb-2 mb-6">
                        <h3 className="font-bold text-xl dark:text-white">Base Points</h3>
                        <button onClick={handleResetDefaults} className="text-xs text-blue-500 hover:text-blue-600 flex items-center gap-1">
                            <RotateCcw size={12}/> Reset Defaults
                        </button>
                    </div>
                    <div className="space-y-4">
                        {[
                            { label: 'Goal Scored', key: 'GOAL' },
                            { label: 'Assist', key: 'ASSIST' },
                            { label: 'Win Bonus', key: 'WIN' },
                            { label: 'Draw Bonus', key: 'DRAW' },
                            { label: 'Clean Sheet (GK)', key: 'CLEAN_SHEET' },
                            { label: 'Own Goal Penalty', key: 'OWN_GOAL', isNegative: true },
                        ].map((item) => (
                            <div key={item.key} className="flex justify-between items-center">
                                <label className={`font-medium ${item.isNegative ? 'text-red-600 dark:text-red-400' : 'text-gray-700 dark:text-gray-300'}`}>{item.label}</label>
                                <input 
                                    type="number"
                                    value={localSettings.basePoints[item.key as keyof typeof BASE_POINTS]}
                                    onChange={(e) => updateBasePoint(item.key as keyof typeof BASE_POINTS, e.target.value)}
                                    className={`w-20 p-2 border rounded-lg text-right font-mono outline-none focus:ring-2 focus:ring-pitch-500 ${item.isNegative ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-900 text-red-700 dark:text-red-400' : 'bg-gray-50 dark:bg-gray-900 border-gray-200 dark:border-gray-700 dark:text-white'}`}
                                />
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <div className="flex justify-between items-center pt-6 border-t dark:border-gray-700">
                <button 
                    onClick={resetData}
                    className="flex items-center gap-2 px-4 py-2 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                >
                    <Database size={18} />
                    Factory Reset App
                </button>
                <button 
                    onClick={handleSaveSettings}
                    className="bg-pitch-600 hover:bg-pitch-500 text-white px-8 py-3 rounded-xl font-bold text-lg shadow-xl flex items-center gap-3 transition-transform hover:scale-105"
                >
                    <Save size={24} />
                    Save Configuration
                </button>
            </div>
        </div>
      )}

      {/* --- MODALS --- */}

      {/* Add/Edit Stadium Modal */}
      {isStadiumModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-fade-in">
          <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl w-full max-w-md shadow-2xl border dark:border-gray-700 animate-slide-up relative">
            <button 
                onClick={() => setIsStadiumModalOpen(false)}
                className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"
            >
                <X size={20} />
            </button>
            <h3 className="text-2xl font-bold mb-6 dark:text-white flex items-center gap-2">
                {editingStadiumId ? <Edit2 className="text-amber-500"/> : <MapPin className="text-pitch-600"/>}
                {editingStadiumId ? 'Edit Venue' : 'Add New Venue'}
            </h3>
            <form onSubmit={handleStadiumSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Venue Name</label>
                <input
                  type="text"
                  required
                  autoFocus
                  placeholder="e.g., Riverside Park"
                  className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white transition-all"
                  value={formStadiumName}
                  onChange={(e) => setFormStadiumName(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Pitch Size</label>
                <select
                  className="w-full p-3 bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-lg focus:ring-2 focus:ring-pitch-500 outline-none dark:text-white transition-all"
                  value={formStadiumSize}
                  onChange={(e) => setFormStadiumSize(e.target.value as StadiumSize)}
                >
                  {Object.values(StadiumSize).map((s) => (
                    <option key={s} value={s}>{s} Size</option>
                  ))}
                </select>
                <p className="text-xs text-gray-500 mt-1">
                    Affects rating multiplier. {formStadiumSize === StadiumSize.SMALL ? 'High scoring expected.' : formStadiumSize === StadiumSize.LARGE ? 'Harder to score.' : 'Balanced play.'}
                </p>
              </div>
              <div className="flex gap-3 mt-6">
                <button
                  type="button"
                  onClick={() => setIsStadiumModalOpen(false)}
                  className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className={`flex-1 px-4 py-2 text-white rounded-lg font-medium shadow-md transition-colors ${editingStadiumId ? 'bg-amber-600 hover:bg-amber-500' : 'bg-pitch-600 hover:bg-pitch-500'}`}
                >
                  {editingStadiumId ? 'Update Venue' : 'Add Venue'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {stadiumToDelete && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
          <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 max-w-sm w-full shadow-2xl border dark:border-gray-700 animate-slide-up">
            <div className="flex items-center gap-3 text-red-600 mb-4">
               <div className="p-2 bg-red-100 dark:bg-red-900/30 rounded-full">
                 <AlertTriangle size={24} />
               </div>
               <h3 className="text-xl font-bold text-gray-900 dark:text-white">Delete Venue?</h3>
            </div>
            <p className="text-gray-600 dark:text-gray-300 mb-2">
               Are you sure you want to delete <strong>{stadiumToDelete.name}</strong>?
            </p>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-6 bg-gray-50 dark:bg-gray-700/50 p-3 rounded-lg border border-gray-100 dark:border-gray-600">
               ⚠️ Past matches played here will keep the stadium name, but this venue won't appear in future selections.
            </p>
            <div className="flex gap-3">
              <button 
                onClick={() => setStadiumToDelete(null)}
                className="flex-1 py-2.5 px-4 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-xl font-medium hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
              >
                Cancel
              </button>
              <button 
                onClick={confirmDeleteStadium}
                className="flex-1 py-2.5 px-4 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold transition-colors shadow-lg"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { StadiumSize, Stadium } from '../types';
import { MapPin, Plus, Trash2, Edit2, X, Search, LayoutGrid, List, AlertTriangle } from 'lucide-react';
import { useToast } from '../context/ToastContext';

const VenueManager: React.FC = () => {
  const { stadiums, addStadium, updateStadium, deleteStadium } = useApp();
  const { showToast } = useToast();

  // -- VENUE MANAGEMENT STATE --
  const [searchQuery, setSearchQuery] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // Modals
  const [isStadiumModalOpen, setIsStadiumModalOpen] = useState(false);
  const [stadiumToDelete, setStadiumToDelete] = useState<Stadium | null>(null);

  // Form State
  const [editingStadiumId, setEditingStadiumId] = useState<string | null>(null);
  const [formStadiumName, setFormStadiumName] = useState('');
  const [formStadiumSize, setFormStadiumSize] = useState<StadiumSize>(StadiumSize.MEDIUM);

  // -- VENUE HANDLERS --
  const filteredStadiums = stadiums.filter(s => s.name.toLowerCase().includes(searchQuery.toLowerCase()));

  const handleOpenAddStadium = () => {
      setEditingStadiumId(null);
      setFormStadiumName('');
      setFormStadiumSize(StadiumSize.MEDIUM);
      setIsStadiumModalOpen(true);
  };

  const handleOpenEditStadium = (s: Stadium) => {
      setEditingStadiumId(s.id);
      setFormStadiumName(s.name);
      setFormStadiumSize(s.size);
      setIsStadiumModalOpen(true);
  };

  const handleStadiumSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formStadiumName.trim()) return;

    if (editingStadiumId) {
        updateStadium({ id: editingStadiumId, name: formStadiumName, size: formStadiumSize });
        showToast('Stadium details updated.', 'success');
    } else {
        addStadium({ id: Date.now().toString(), name: formStadiumName, size: formStadiumSize });
        showToast('New venue added.', 'success');
    }
    setIsStadiumModalOpen(false);
  };

  const confirmDeleteStadium = () => {
      if (stadiumToDelete) {
          deleteStadium(stadiumToDelete.id);
          showToast('Venue removed.', 'info');
          setStadiumToDelete(null);
      }
  };

  const sizeColor = (size: StadiumSize) => {
      switch(size) {
          case StadiumSize.SMALL: return 'bg-emerald-100 text-emerald-800 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-700';
          case StadiumSize.MEDIUM: return 'bg-blue-100 text-blue-800 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-700';
          case StadiumSize.LARGE: return 'bg-purple-100 text-purple-800 border-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-700';
          default: return 'bg-gray-100';
      }
  };

  return (
    <div className="space-y-6 animate-fade-in relative">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-3xl font-bold dark:text-white flex items-center gap-3">
               <MapPin className="text-pitch-600" size={32} />
               Venues
           </h2>
