                      <div className={`h-28 ${sizeColor(s.size).split(' ')[0]} bg-opacity-40 relative overflow-hidden flex items-center justify-center`}>
                           <MapPin className="text-current opacity-20 w-16 h-16" />
                           <div className="absolute top-2 right-2">
                               <span className={`px-2 py-1 rounded text-xs font-bold uppercase bg-white/80 dark:bg-black/50 backdrop-blur-sm border ${sizeColor(s.size)}`}>
                                  {s.size} Pitch
